export enum BookingStatus {
  CONFIRMED = 'CONFIRMED',
  PENDING = 'PENDING',
  CANCELED = 'CANCELED',
  MAINTENANCE = 'MAINTENANCE',
  BLOCKED = 'BLOCKED'
}

export interface Space {
  id: string;
  name: string;
  type: 'SAUNA' | 'MASSAGE' | 'POOL' | 'RELAX' | 'HAMMAM';
  capacity: number;
}

export interface Booking {
  id: string;
  spaceId: string;
  customerName: string;
  serviceName: string; // e.g., "Deep Tissue", "1h Access"
  startTime: string; // HH:mm format for simplicity in this demo
  durationMinutes: number;
  status: BookingStatus;
  notes?: string;
}

export interface TimeSlot {
  time: string; // HH:mm
  display: string;
}

export interface DailyStats {
  revenue: number;
  occupancyRate: number;
  totalBookings: number;
}

import { GoogleGenAI } from "@google/genai";
import { Booking, Space } from '../types';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-3-flash-preview";

export const generateSmartScheduleSuggestion = async (
  request: string,
  spaces: Space[],
  existingBookings: Booking[]
): Promise<string> => {
  try {
    const spacesStr = JSON.stringify(spaces.map(s => ({ id: s.id, name: s.name })));
    const bookingsStr = JSON.stringify(existingBookings.map(b => ({
      space: b.spaceId,
      start: b.startTime,
      duration: b.durationMinutes
    })));

    const prompt = `
      You are an expert wellness center receptionist AI.
      Current Spaces: ${spacesStr}
      Current Bookings Today: ${bookingsStr}

      User Request: "${request}"

      Based on the request, suggest a specific booking slot (Space, Start Time, Duration).
      Check for conflicts. If there is a conflict, suggest the nearest available time.
      Return the answer in a concise, friendly manner.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });

    return response.text || "Sorry, I couldn't generate a suggestion.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "AI Service unavailable. Please check API Key.";
  }
};

export const analyzeDailySentiment = async (bookings: Booking[]): Promise<string> => {
   try {
    const summary = bookings.map(b => `${b.serviceName} (${b.durationMinutes}m)`).join(', ');
    const prompt = `
      Analyze the day's schedule based on these services: ${summary}.
      Give a 2-sentence summary of the operational load (e.g., "Heavy massage focus", "Relaxed morning").
      Be professional.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });

    return response.text || "No analysis available.";
  } catch (error) {
    return "Analysis unavailable.";
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({
  children,
  variant = 'primary',
  size = 'md',
  isLoading,
  className = '',
  ...props
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-teal-600 text-white hover:bg-teal-700 focus:ring-teal-500 shadow-sm",
    secondary: "bg-white text-slate-700 border border-slate-300 hover:bg-slate-50 focus:ring-slate-500 shadow-sm",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500 shadow-sm",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 focus:ring-slate-500",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base",
  };

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

import React, { useEffect, useRef } from 'react';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      document.body.style.overflow = 'hidden';
    }
    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm transition-opacity">
      <div
        ref={modalRef}
        className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden transform transition-all animate-in fade-in zoom-in-95 duration-200"
      >
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800">{title}</h3>
          <button
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 transition-colors"
          >
            <X size={20} />
          </button>
        </div>
        <div className="p-6">
          {children}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BookingStatus, Space } from '../types';
import { Button } from './Button';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
}

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData }) => {
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || spaces[0]?.id || '',
    startTime: initialData?.startTime || '09:00',
    durationMinutes: initialData?.durationMinutes || 60,
    status: initialData?.status || BookingStatus.CONFIRMED,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
        ...formData,
        durationMinutes: Number(formData.durationMinutes)
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <label className="block text-sm font-medium text-slate-700 mb-1">Customer Name</label>
        <input
          type="text"
          name="customerName"
          required
          value={formData.customerName}
          onChange={handleChange}
          className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
          placeholder="Jane Doe"
        />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Service</label>
          <input
            type="text"
            name="serviceName"
            required
            value={formData.serviceName}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
            placeholder="Massage"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
          >
            {Object.values(BookingStatus).map(s => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>
      </div>

      <div>
        <label className="block text-sm font-medium text-slate-700 mb-1">Space</label>
        <select
          name="spaceId"
          value={formData.spaceId}
          onChange={handleChange}
          className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
        >
          {spaces.map(space => (
            <option key={space.id} value={space.id}>{space.name} ({space.type})</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Start Time</label>
          <input
            type="time"
            name="startTime"
            required
            value={formData.startTime}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Duration (min)</label>
          <input
            type="number"
            name="durationMinutes"
            required
            min="15"
            step="15"
            value={formData.durationMinutes}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2 text-sm focus:border-teal-500 focus:ring-teal-500"
          />
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-4">
        <Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button>
        <Button type="submit">Save Booking</Button>
      </div>
    </form>
  );
};

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Booking, BookingStatus } from '../types';
import { Users, DollarSign, CalendarCheck, Activity } from 'lucide-react';

interface DashboardProps {
  bookings: Booking[];
}

const COLORS = ['#0d9488', '#f59e0b', '#ef4444', '#64748b'];

export const Dashboard: React.FC<DashboardProps> = ({ bookings }) => {
  const stats = useMemo(() => {
    const total = bookings.length;
    const confirmed = bookings.filter(b => b.status === BookingStatus.CONFIRMED).length;
    // Mock revenue calculation: 1 minute = $1.5
    const revenue = bookings.reduce((acc, curr) => acc + (curr.durationMinutes * 1.5), 0);
    const occupancy = Math.round((bookings.reduce((acc, curr) => acc + curr.durationMinutes, 0) / (12 * 60 * 6)) * 100); // approx logic

    return { total, confirmed, revenue, occupancy };
  }, [bookings]);

  const typeData = useMemo(() => {
     const counts: Record<string, number> = {};
     bookings.forEach(b => {
         counts[b.status] = (counts[b.status] || 0) + 1;
     });
     return Object.keys(counts).map(key => ({ name: key, value: counts[key] }));
  }, [bookings]);

  const timeDistribution = useMemo(() => {
      // Group by hour
      const dist = Array(12).fill(0).map((_, i) => ({ hour: `${8 + i}:00`, count: 0 }));
      bookings.forEach(b => {
          const hour = parseInt(b.startTime.split(':')[0]);
          if (hour >= 8 && hour < 20) {
              dist[hour - 8].count += 1;
          }
      });
      return dist;
  }, [bookings]);

  const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
      <div>
        <p className="text-sm text-slate-500 font-medium mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
      </div>
      <div className={`p-3 rounded-full ${color} bg-opacity-10`}>
        <Icon size={24} className={color.replace('bg-', 'text-')} />
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Bookings" value={stats.total} icon={CalendarCheck} color="bg-blue-500" />
        <StatCard title="Confirmed" value={stats.confirmed} icon={Users} color="bg-teal-500" />
        <StatCard title="Est. Revenue" value={`$${stats.revenue}`} icon={DollarSign} color="bg-emerald-500" />
        <StatCard title="Occupancy Rate" value={`${stats.occupancy}%`} icon={Activity} color="bg-orange-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Booking Status Distribution</h4>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={typeData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {typeData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-4 mt-4 text-sm text-slate-600">
              {typeData.map((entry, index) => (
                  <div key={entry.name} className="flex items-center gap-2">
                      <span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[index % COLORS.length]}}></span>
                      {entry.name}
                  </div>
              ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Hourly Activity</h4>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={timeDistribution}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="hour" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                <Bar dataKey="count" fill="#0d9488" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE, SLOT_INTERVAL } from '../constants';
import { Clock, Plus } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const getBookingStyles = (booking: Booking) => {
    const startMins = timeToMinutes(booking.startTime) - (OPENING_HOUR * 60);
    const width = booking.durationMinutes * PIXELS_PER_MINUTE;
    const left = startMins * PIXELS_PER_MINUTE;

    let bgClass = "bg-teal-100 border-teal-300 text-teal-800";
    if (booking.status === BookingStatus.MAINTENANCE) bgClass = "bg-red-100 border-red-300 text-red-800";
    if (booking.status === BookingStatus.PENDING) bgClass = "bg-amber-100 border-amber-300 text-amber-800";
    if (booking.status === BookingStatus.BLOCKED) bgClass = "bg-slate-200 border-slate-400 text-slate-800";

    return {
      left: `${left}px`,
      width: `${width}px`,
      className: `absolute top-1 bottom-1 rounded-md border text-xs p-1 overflow-hidden whitespace-nowrap cursor-pointer hover:shadow-md transition-all z-10 ${bgClass}`
    };
  };

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    // Only trigger if clicking the background, not a booking
    if ((e.target as HTMLElement).closest('.booking-block')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    // Snap to nearest 15 mins
    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="flex border-b border-slate-200 bg-slate-50 sticky top-0 z-20">
        <div className="w-48 flex-shrink-0 p-4 font-semibold text-slate-700 flex items-center border-r border-slate-200">
          Resources
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
             {/* Fake overflow container to match width */}
            <div style={{ width: `${gridWidth}px` }} className="h-12 relative flex items-center">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute text-xs text-slate-500 font-medium transform -translate-x-1/2 flex flex-col items-center"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span>{hour}:00</span>
                        <div className="h-1 w-px bg-slate-300 mt-1"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative">
        <div className="min-w-max">
            {spaces.map(space => (
            <div key={space.id} className="flex border-b border-slate-100 group hover:bg-slate-50 transition-colors">
                <div className="w-48 flex-shrink-0 p-4 border-r border-slate-200 bg-white sticky left-0 z-10 flex flex-col justify-center">
                    <span className="font-medium text-slate-700 text-sm">{space.name}</span>
                    <span className="text-xs text-slate-400 uppercase tracking-wider mt-1">{space.type}</span>
                </div>

                <div 
                    className="relative h-16 border-r border-slate-100 bg-[linear-gradient(90deg,transparent_29px,#f1f5f9_30px)] bg-[length:75px_100%]"
                    style={{ width: `${gridWidth}px` }}
                    onClick={(e) => handleGridClick(e, space.id)}
                >
                    {/* Hour Vertical Lines */}
                     {timeMarkers.map(hour => (
                        <div 
                            key={`line-${hour}`} 
                            className="absolute top-0 bottom-0 border-l border-slate-200 border-dashed pointer-events-none"
                            style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                        />
                    ))}

                    {/* Bookings */}
                    {bookings
                        .filter(b => b.spaceId === space.id)
                        .map(booking => {
                            const styles = getBookingStyles(booking);
                            return (
                                <div
                                    key={booking.id}
                                    style={{ left: styles.left, width: styles.width }}
                                    className={`booking-block ${styles.className} group/booking`}
                                    onClick={() => onBookingClick(booking)}
                                >
                                    <div className="font-semibold truncate">{booking.serviceName}</div>
                                    <div className="truncate opacity-90">{booking.customerName}</div>
                                </div>
                            );
                    })}

                    {/* Hover Effect for Add */}
                    <div className="absolute inset-0 opacity-0 group-hover:opacity-100 pointer-events-none flex items-center justify-center">
                        <Plus className="text-slate-300 w-6 h-6" />
                    </div>
                </div>
            </div>
            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Calendar, LayoutDashboard, Settings, Sparkles, Plus, Search, MessageSquare } from 'lucide-react';
import { Space, Booking, BookingStatus } from './types';
import { MOCK_SPACES, MOCK_BOOKINGS } from './constants';
import { PlanningGrid } from './components/PlanningGrid';
import { Dashboard } from './components/Dashboard';
import { Modal } from './components/Modal';
import { BookingForm } from './components/BookingForm';
import { Button } from './components/Button';
import { generateSmartScheduleSuggestion, analyzeDailySentiment } from './services/geminiService';

enum View {
  DASHBOARD = 'DASHBOARD',
  CALENDAR = 'CALENDAR',
  SETTINGS = 'SETTINGS',
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.CALENDAR);
  const [spaces] = useState<Space[]>(MOCK_SPACES);
  const [bookings, setBookings] = useState<Booking[]>(MOCK_BOOKINGS);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [initialFormState, setInitialFormState] = useState<any>(null);

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showAiPanel, setShowAiPanel] = useState(false);

  // Booking Handlers
  const handleSlotClick = (spaceId: string, time: string) => {
    setEditingBooking(null);
    setInitialFormState({ spaceId, startTime: time, durationMinutes: 60 });
    setIsModalOpen(true);
  };

  const handleBookingClick = (booking: Booking) => {
    setEditingBooking(booking);
    setInitialFormState(booking);
    setIsModalOpen(true);
  };

  const handleFormSubmit = (data: any) => {
    if (editingBooking) {
      // Update
      setBookings(prev => prev.map(b => b.id === editingBooking.id ? { ...data, id: b.id } : b));
    } else {
      // Create
      const newBooking: Booking = {
        ...data,
