import React, { useRef } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE } from '../constants';
import { Plus } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const getBookingStyles = (booking: Booking) => {
    const startMins = timeToMinutes(booking.startTime) - (OPENING_HOUR * 60);
    const width = booking.durationMinutes * PIXELS_PER_MINUTE;
    const left = startMins * PIXELS_PER_MINUTE;

    let bgClass = "bg-teal-100 border-teal-300 text-teal-800";
    if (booking.status === BookingStatus.MAINTENANCE) bgClass = "bg-red-100 border-red-300 text-red-800";
    if (booking.status === BookingStatus.PENDING) bgClass = "bg-amber-100 border-amber-300 text-amber-800";
    if (booking.status === BookingStatus.BLOCKED) bgClass = "bg-slate-200 border-slate-400 text-slate-800";

    return {
      left: `${left}px`,
      width: `${width}px`,
      className: `absolute top-1 bottom-1 rounded-md border text-xs p-1 overflow-hidden whitespace-nowrap cursor-pointer hover:shadow-md transition-all z-10 ${bgClass}`
    };
  };

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    if ((e.target as HTMLElement).closest('.booking-block')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="flex border-b border-slate-200 bg-slate-50 sticky top-0 z-20">
        <div className="w-32 md:w-48 flex-shrink-0 p-4 font-semibold text-slate-700 flex items-center border-r border-slate-200 text-sm md:text-base">
          Espaces
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
             {/* Fake overflow container to match width */}
            <div style={{ width: `${gridWidth}px` }} className="h-12 relative flex items-center">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute text-xs text-slate-500 font-medium transform -translate-x-1/2 flex flex-col items-center"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span>{hour}h</span>
                        <div className="h-1 w-px bg-slate-300 mt-1"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative">
        <div className="min-w-max">
            {spaces.map(space => (
            <div key={space.id} className="flex border-b border-slate-100 group hover:bg-slate-50 transition-colors">
                <div className="w-32 md:w-48 flex-shrink-0 p-2 md:p-4 border-r border-slate-200 bg-white sticky left-0 z-10 flex flex-col justify-center">
                    <span className="font-medium text-slate-700 text-xs md:text-sm truncate">{space.name}</span>
                    <span className="text-[10px] md:text-xs text-slate-400 uppercase tracking-wider mt-0.5 md:mt-1">{space.type}</span>
                </div>

                <div 
                    className="relative h-16 border-r border-slate-100 bg-[linear-gradient(90deg,transparent_29px,#f1f5f9_30px)] bg-[length:75px_100%]"
                    style={{ width: `${gridWidth}px` }}
                    onClick={(e) => handleGridClick(e, space.id)}
                >
                    {/* Hour Vertical Lines */}
                     {timeMarkers.map(hour => (
                        <div 
                            key={`line-${hour}`} 
                            className="absolute top-0 bottom-0 border-l border-slate-200 border-dashed pointer-events-none"
                            style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                        />
                    ))}

                    {/* Bookings */}
                    {bookings
                        .filter(b => b.spaceId === space.id)
                        .map(booking => {
                            const styles = getBookingStyles(booking);
                            return (
                                <div
                                    key={booking.id}
                                    style={{ left: styles.left, width: styles.width }}
                                    className={`booking-block ${styles.className} group/booking`}
                                    onClick={() => onBookingClick(booking)}
                                >
                                    <div className="font-semibold truncate px-1">{booking.serviceName}</div>
                                    <div className="truncate opacity-90 px-1 hidden md:block">{booking.customerName}</div>
                                </div>
                            );
                    })}

                    {/* Hover Effect for Add */}
                    <div className="absolute inset-0 opacity-0 group-hover:opacity-100 pointer-events-none flex items-center justify-center">
                        <Plus className="text-slate-300 w-6 h-6" />
                    </div>
                </div>
            </div>
            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar, LayoutDashboard, Settings, Sparkles, Plus, Search, MessageSquare, Menu, X } from 'lucide-react';
import { Space, Booking } from './types';
import { MOCK_SPACES, MOCK_BOOKINGS } from './constants';
import { PlanningGrid } from './components/PlanningGrid';
import { Dashboard } from './components/Dashboard';
import { Modal } from './components/Modal';
import { BookingForm } from './components/BookingForm';
import { Button } from './components/Button';
import { generateSmartScheduleSuggestion, analyzeDailySentiment } from './services/geminiService';

enum View {
  DASHBOARD = 'DASHBOARD',
  CALENDAR = 'CALENDAR',
  SETTINGS = 'SETTINGS',
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.CALENDAR);
  const [spaces] = useState<Space[]>(MOCK_SPACES);
  const [bookings, setBookings] = useState<Booking[]>(MOCK_BOOKINGS);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [initialFormState, setInitialFormState] = useState<any>(null);

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showAiPanel, setShowAiPanel] = useState(false);

  // Booking Handlers
  const handleSlotClick = (spaceId: string, time: string) => {
    setEditingBooking(null);
    setInitialFormState({ spaceId, startTime: time, durationMinutes: 60 });
    setIsModalOpen(true);
  };

  const handleBookingClick = (booking: Booking) => {
    setEditingBooking(booking);
    setInitialFormState(booking);
    setIsModalOpen(true);
  };

  const handleFormSubmit = (data: any) => {
    if (editingBooking) {
      // Update
      setBookings(prev => prev.map(b => b.id === editingBooking.id ? { ...data, id: b.id } : b));
    } else {
      // Create
      const newBooking: Booking = {
        ...data,
        id: Math.random().toString(36).substr(2, 9),
      };
      setBookings(prev => [...prev, newBooking]);
    }
    setIsModalOpen(false);
    setEditingBooking(null);
  };

  // AI Handlers
  const handleAiAction = async () => {
    if (!aiPrompt.trim()) return;
    setIsAiLoading(true);
    setAiResponse('');

    // Check if it's an analysis request
    if (aiPrompt.toLowerCase().includes('analyse') || aiPrompt.toLowerCase().includes('résumé')) {
        const sentiment = await analyzeDailySentiment(bookings);
        setAiResponse(sentiment);
    } else {
        const suggestion = await generateSmartScheduleSuggestion(aiPrompt, spaces, bookings);
        setAiResponse(suggestion);
    }
    setIsAiLoading(false);
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  return (
    <div className="flex h-screen bg-slate-50 text-slate-800 font-sans overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col shadow-xl transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0
      `}>
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-teal-500 rounded-lg flex items-center justify-center">
                  <Sparkles size={18} className="text-white" />
              </div>
              <span className="font-bold text-lg tracking-tight">ZenSpace</span>
            </div>
            <button onClick={toggleSidebar} className="md:hidden text-slate-400 hover:text-white">
              <X size={20} />
            </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => { setCurrentView(View.CALENDAR); setIsSidebarOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.CALENDAR ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Calendar size={20} />
            <span className="font-medium">Planning</span>
          </button>

          <button 
             onClick={() => { setCurrentView(View.DASHBOARD); setIsSidebarOpen(false); }}
             className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.DASHBOARD ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            <span className="font-medium">Tableau de bord</span>
          </button>

          <button 
             onClick={() => { setCurrentView(View.SETTINGS); setIsSidebarOpen(false); }}
             className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.SETTINGS ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings size={20} />
            <span className="font-medium">Paramètres</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
           <div className="bg-slate-800 rounded-lg p-4 cursor-pointer hover:bg-slate-700 transition-colors" onClick={() => setShowAiPanel(!showAiPanel)}>
               <div className="flex items-center gap-3 mb-2">
                   <div className="bg-gradient-to-br from-purple-500 to-indigo-500 p-2 rounded-md">
                        <MessageSquare size={16} className="text-white" />
                   </div>
                   <span className="font-semibold text-sm">Assistant IA</span>
               </div>
               <p className="text-xs text-slate-400">Demander de l'aide...</p>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative overflow-hidden w-full">
        {/* Top Bar */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-6 flex-shrink-0">
          <div className="flex items-center gap-3">
            <button onClick={toggleSidebar} className="md:hidden text-slate-500 hover:text-slate-700">
              <Menu size={24} />
            </button>
            <h2 className="text-lg md:text-xl font-bold text-slate-800 truncate">
              {currentView === View.CALENDAR && 'Planning'}
              {currentView === View.DASHBOARD && 'Vue d\'ensemble'}
              {currentView === View.SETTINGS && 'Configuration'}
            </h2>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative hidden md:block">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
                <input type="text" placeholder="Rechercher..." className="pl-10 pr-4 py-2 bg-slate-100 rounded-full text-sm border-transparent focus:bg-white focus:ring-2 focus:ring-teal-500 transition-all outline-none w-48 lg:w-64" />
            </div>
            <Button onClick={() => { setEditingBooking(null); setInitialFormState(null); setIsModalOpen(true); }} className="whitespace-nowrap">
                <Plus size={18} className="md:mr-2" /> 
                <span className="hidden md:inline">Nouvelle Réservation</span>
            </Button>
          </div>
        </header>

        {/* Dynamic View Area */}
        <div className="flex-1 overflow-auto p-4 md:p-6 bg-slate-50/50 relative">
          {currentView === View.CALENDAR && (
            <PlanningGrid 
                spaces={spaces} 
                bookings={bookings} 
                onSlotClick={handleSlotClick} 
                onBookingClick={handleBookingClick}
            />
          )}
          {currentView === View.DASHBOARD && (
            <Dashboard bookings={bookings} />
          )}
          {currentView === View.SETTINGS && (
              <div className="flex items-center justify-center h-full text-slate-400">
                  Section Paramètres (À venir)
              </div>
          )}

           {/* AI Panel Overlay */}
           {showAiPanel && (
               <div className="absolute right-0 bottom-0 md:right-6 md:bottom-6 w-full md:w-96 h-[50vh] md:h-auto md:max-h-[600px] bg-white md:rounded-xl shadow-2xl border-t md:border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-right duration-300 z-50">
                   <div className="bg-gradient-to-r from-purple-600 to-indigo-600 p-4 flex justify-between items-center text-white">
                       <div className="flex items-center gap-2">
                            <Sparkles size={18} />
                            <span className="font-semibold">Assistant Gemini</span>
                       </div>
                       <button onClick={() => setShowAiPanel(false)} className="hover:bg-white/20 p-1 rounded"><X size={16} /></button>
                   </div>
                   <div className="p-4 flex-1 overflow-y-auto bg-slate-50 min-h-[200px]">
                        {aiResponse ? (
                            <div className="bg-white p-3 rounded-lg shadow-sm text-sm border border-slate-200 mb-4 whitespace-pre-wrap">
                                {aiResponse}
                            </div>
                        ) : (
                            <div className="text-center text-slate-400 text-sm mt-8">
                                <p>Essayez de demander :</p>
                                <ul className="mt-2 space-y-2 text-xs">
                                    <li className="bg-white p-2 rounded cursor-pointer hover:text-purple-600" onClick={() => setAiPrompt("Trouve un créneau de 1h pour massage et sauna")}>"Trouve un créneau de 1h..."</li>
                                    <li className="bg-white p-2 rounded cursor-pointer hover:text-purple-600" onClick={() => setAiPrompt("Analyse le sentiment du planning d'aujourd'hui")}>"Analyse le planning..."</li>
                                </ul>
                            </div>
                        )}
                   </div>
                   <div className="p-3 border-t border-slate-100 bg-white">
                       <textarea 
                            value={aiPrompt}
                            onChange={(e) => setAiPrompt(e.target.value)}
                            placeholder="Votre demande..." 
                            className="w-full text-sm p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none resize-none h-16 md:h-20"
                       />
                       <div className="flex justify-end mt-2">
                           <Button size="sm" onClick={handleAiAction} isLoading={isAiLoading} className="bg-purple-600 hover:bg-purple-700">
                               Envoyer
                           </Button>
                       </div>
                   </div>
               </div>
           )}
        </div>
      </main>

      {/* Booking Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={editingBooking ? "Modifier Réservation" : "Nouvelle Réservation"}
      >
        <BookingForm
            spaces={spaces}
            onSubmit={handleFormSubmit}
            onCancel={() => setIsModalOpen(false)}
            initialData={initialFormState}
        />
      </Modal>
    </div>
  );
};

