import React, { useRef } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE } from '../constants';
import { Plus, Users } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

// Helper to calculate overlaps for visual stacking
const calculateLayout = (spaceBookings: Booking[]) => {
  const sorted = [...spaceBookings].sort((a, b) => timeToMinutes(a.startTime) - timeToMinutes(b.startTime));
  const columns: Booking[][] = [];

  sorted.forEach(booking => {
    let placed = false;
    for (const col of columns) {
      const lastInCol = col[col.length - 1];
      const lastEnd = timeToMinutes(lastInCol.startTime) + lastInCol.durationMinutes + (lastInCol.breakMinutes || 0);
      const currentStart = timeToMinutes(booking.startTime);

      if (currentStart >= lastEnd) {
        col.push(booking);
        placed = true;
        break;
      }
    }
    if (!placed) {
      columns.push([booking]);
    }
  });
  return columns;
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    if ((e.target as HTMLElement).closest('.booking-block')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="flex border-b border-slate-200 bg-slate-50/80 backdrop-blur-sm sticky top-0 z-20">
        <div className="w-40 md:w-56 flex-shrink-0 p-4 font-semibold text-slate-700 flex items-center border-r border-slate-200 text-sm md:text-base bg-slate-50">
          Espaces
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
            <div style={{ width: `${gridWidth}px` }} className="h-12 relative flex items-center">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute text-xs text-slate-400 font-medium transform -translate-x-1/2 flex flex-col items-center"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span>{hour}h</span>
                        <div className="h-1.5 w-px bg-slate-300 mt-1"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative">
        <div className="min-w-max">
            {spaces.map(space => {
                const spaceBookings = bookings.filter(b => b.spaceId === space.id);
                // Simple visual stacking logic requires knowing how many concurrent items exist at any point
                // For a simpler "pro" look, we just allow them to overlap slightly or use height percentage if crowded
                // But full robust stacking in one row is complex. 
                // Let's use a simplified approach: render all, but adjust top/height based on index if they overlap.

                return (
                <div key={space.id} className="flex border-b border-slate-100 group hover:bg-slate-50 transition-colors min-h-[5rem]">
                    <div className="w-40 md:w-56 flex-shrink-0 p-3 border-r border-slate-200 bg-white sticky left-0 z-20 flex flex-col justify-center shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                        <div className="flex justify-between items-start">
                             <span className="font-semibold text-slate-700 text-sm truncate">{space.name}</span>
                             <div className="flex items-center text-slate-400 text-xs gap-1 bg-slate-100 px-1.5 py-0.5 rounded-full">
                                <Users size={10} /> {space.capacity}
                             </div>
                        </div>
                        <span className="text-[11px] text-slate-400 uppercase tracking-wider mt-1">{space.type}</span>
                    </div>

                    <div 
                        className="relative h-20 border-r border-slate-100 bg-[linear-gradient(90deg,transparent_29px,#f1f5f9_30px)] bg-[length:75px_100%]"
                        style={{ width: `${gridWidth}px` }}
                        onClick={(e) => handleGridClick(e, space.id)}
                    >
                        {/* Hour Vertical Lines */}
                        {timeMarkers.map(hour => (
                            <div 
                                key={`line-${hour}`} 
                                className="absolute top-0 bottom-0 border-l border-slate-100 border-dashed pointer-events-none"
                                style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                            />
                        ))}

                        {/* Bookings */}
                        {spaceBookings.map((booking, index) => {
                             // Check for overlaps with THIS booking to determine vertical offset
                             // This is a naive visual stacking. 
                             // Find other bookings that overlap with this one
                             const myStart = timeToMinutes(booking.startTime);
                             const myEnd = myStart + booking.durationMinutes + (booking.breakMinutes || 0);

                             const overlaps = spaceBookings.filter(b => {
                                 if (b.id === booking.id) return false;
                                 const otherStart = timeToMinutes(b.startTime);
                                 const otherEnd = otherStart + b.durationMinutes + (b.breakMinutes || 0);
                                 return (myStart < otherEnd && myEnd > otherStart);
                             });

                             // Determine "lane" based on simple index in filtered array (not perfect but functional for demo)
                             // For a true pro scheduler, we'd need a complete lane packing algorithm.
                             // Here we just offset by a bit if there is overlap to show depth.
                             const overlapCount = overlaps.length;
                             const isOverlapped = overlapCount > 0;

                             // Visual Calculations
                             const startMins = myStart - (OPENING_HOUR * 60);
                             const width = booking.durationMinutes * PIXELS_PER_MINUTE;
                             const breakWidth = (booking.breakMinutes || 0) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             let bgClass = "bg-teal-100 border-teal-300 text-teal-800 shadow-sm";
                             if (booking.status === BookingStatus.MAINTENANCE) bgClass = "bg-red-100 border-red-300 text-red-800";
                             if (booking.status === BookingStatus.PENDING) bgClass = "bg-amber-100 border-amber-300 text-amber-800";
                             if (booking.status === BookingStatus.BLOCKED) bgClass = "bg-slate-200 border-slate-400 text-slate-800";

                             // If capacity > 1, we stack them vertically with fixed height
                             // We cheat a bit by using the index of the booking in the space array modulo capacity
                             // to spread them out vertically if they overlap.
                             const laneIndex = index % Math.max(1, space.capacity);
                             const heightPercent = space.capacity > 1 ? Math.max(30, 90 / space.capacity) : 80;
                             const topPercent = space.capacity > 1 ? (laneIndex * (95 / space.capacity)) : 10;

                             return (
                                <React.Fragment key={booking.id}>
                                    <div
                                        style={{ 
                                            left: `${left}px`, 
                                            width: `${width}px`,
                                            top: `${topPercent}%`,
                                            height: `${heightPercent}%`,
                                            zIndex: 10 + index
                                        }}
                                        className={`booking-block absolute rounded-md border text-xs px-2 flex flex-col justify-center overflow-hidden whitespace-nowrap cursor-pointer hover:shadow-md hover:brightness-95 transition-all ${bgClass}`}
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onBookingClick(booking);
                                        }}
                                        title={`${booking.customerName} - ${booking.serviceName}`}
                                    >
                                        <div className="font-semibold truncate text-[11px] leading-tight">{booking.serviceName}</div>
                                        {heightPercent > 40 && <div className="truncate opacity-80 text-[10px]">{booking.customerName}</div>}
                                    </div>

                                    {booking.breakMinutes && booking.breakMinutes > 0 && (
                                        <div 
                                            className="absolute z-0 bg-slate-100 rounded-r-md border-y border-r border-slate-200/50"
                                            style={{
                                                left: `${left + width}px`,
                                                width: `${breakWidth}px`,
                                                top: `${topPercent}%`,
                                                height: `${heightPercent}%`,
                                                backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 2px, #cbd5e1 2px, #cbd5e1 4px)'
                                            }}
                                            title="Temps de pause / Nettoyage"
                                        />
                                    )}
                                </React.Fragment>
                            );
                        })}

                        {/* Hover Plus */}
                        <div className="absolute inset-0 opacity-0 group-hover:opacity-100 pointer-events-none flex items-center justify-center">
                            <Plus className="text-slate-300 w-6 h-6" />
                        </div>
                    </div>
                </div>
                );
            })}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BookingStatus, Space, Booking } from '../types';
import { Button } from './Button';
import { Clock, Calendar as CalendarIcon, AlertCircle } from 'lucide-react';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
  currentBookings: Booking[]; // Need to know existing bookings for capacity check
}

const STATUS_LABELS: Record<BookingStatus, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.MAINTENANCE]: 'Maintenance',
  [BookingStatus.BLOCKED]: 'Bloqué',
};

const timeToMins = (t: string) => {
    const [h, m] = t.split(':').map(Number);
    return h * 60 + m;
}

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData, currentBookings }) => {
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || spaces[0]?.id || '',
    date: initialData?.date || new Date().toISOString().split('T')[0],
    startTime: initialData?.startTime || '09:00',
    durationMinutes: initialData?.durationMinutes || 60,
    breakMinutes: initialData?.breakMinutes || 0,
    status: initialData?.status || BookingStatus.CONFIRMED,
  });

  const [error, setError] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setError(null);
  };

  const checkCapacity = (): boolean => {
      // Find space capacity
      const space = spaces.find(s => s.id === formData.spaceId);
      if (!space) return true;

      const newStart = timeToMins(formData.startTime);
      const newEnd = newStart + Number(formData.durationMinutes) + Number(formData.breakMinutes);

      // Filter bookings for this space on this date
      const concurrent = currentBookings.filter(b => {
          if (b.spaceId !== formData.spaceId) return false;
          if (b.date !== formData.date) return false;
          if (initialData && b.id === initialData.id) return false; // Exclude self if editing
          if (b.status === BookingStatus.CANCELED) return false;

          const bStart = timeToMins(b.startTime);
          const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);

          // Check overlap
          return (newStart < bEnd && newEnd > bStart);
      });

      if (concurrent.length >= space.capacity) {
          setError(`Capacité atteinte pour cet espace (${space.capacity} max) sur ce créneau.`);
          return false;
      }
      return true;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!checkCapacity()) return;

    onSubmit({
        ...formData,
        durationMinutes: Number(formData.durationMinutes),
        breakMinutes: Number(formData.breakMinutes)
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center gap-2">
              <AlertCircle size={16} />
              {error}
          </div>
      )}

      <div>
        <label className="block text-sm font-medium text-slate-700 mb-1">Nom du client</label>
        <input
          type="text"
          name="customerName"
          required
          value={formData.customerName}
          onChange={handleChange}
          className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
          placeholder="ex: Jean Dupont"
        />
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Service / Soin</label>
          <input
            type="text"
            name="serviceName"
            required
            value={formData.serviceName}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
            placeholder="ex: Massage Suédois"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Statut</label>
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
          >
            {Object.values(BookingStatus).map(s => (
              <option key={s} value={s}>{STATUS_LABELS[s]}</option>
            ))}
          </select>
        </div>
      </div>

      <div>
        <label className="block text-sm font-medium text-slate-700 mb-1">Espace</label>
        <select
          name="spaceId"
          value={formData.spaceId}
          onChange={handleChange}
          className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
        >
          {spaces.map(space => (
            <option key={space.id} value={space.id}>{space.name} ({space.type} - Max {space.capacity})</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-2 gap-4">
         <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Date</label>
          <div className="relative">
              <input
                type="date"
                name="date"
                required
                value={formData.date}
                onChange={handleChange}
                className="w-full rounded-lg border-slate-200 border p-2.5 pl-9 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
              />
              <CalendarIcon size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
          </div>
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Heure Début</label>
          <input
            type="time"
            name="startTime"
            required
            value={formData.startTime}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
          />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Durée (min)</label>
          <input
            type="number"
            name="durationMinutes"
            required
            min="15"
            step="5"
            value={formData.durationMinutes}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all"
          />
        </div>
         <div>
          <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
             Pause <Clock size={12} className="text-slate-400"/>
          </label>
          <select
            name="breakMinutes"
            value={formData.breakMinutes}
            onChange={handleChange}
            className="w-full rounded-lg border-slate-200 border p-2.5 text-sm focus:border-teal-500 focus:ring-teal-500 transition-all bg-slate-50"
          >
            <option value="0">Aucune</option>
            <option value="15">15 min</option>
            <option value="30">30 min</option>
            <option value="45">45 min</option>
            <option value="60">1h</option>
          </select>
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-6 border-t border-slate-100 mt-4">
        <Button type="button" variant="secondary" onClick={onCancel}>Annuler</Button>
        <Button type="submit">Enregistrer</Button>
      </div>
    </form>
  );
};

import React, { useState, useEffect } from 'react';
import { Calendar, LayoutDashboard, Settings, Sparkles, Plus, Search, MessageSquare, Menu, X, Loader2, ChevronLeft, ChevronRight } from 'lucide-react';
import { Space, Booking } from './types';
import { PlanningGrid } from './components/PlanningGrid';
import { Dashboard } from './components/Dashboard';
import { Modal } from './components/Modal';
import { BookingForm } from './components/BookingForm';
import { Button } from './components/Button';
import { SpaceManager } from './components/SpaceManager';
import { generateSmartScheduleSuggestion, analyzeDailySentiment } from './services/geminiService';
import { supabase } from './supabaseClient';

enum View {
  DASHBOARD = 'DASHBOARD',
  CALENDAR = 'CALENDAR',
  SETTINGS = 'SETTINGS',
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.CALENDAR);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Data State
  const [spaces, setSpaces] = useState<Space[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(true);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [initialFormState, setInitialFormState] = useState<any>(null);

  // AI State
  const [aiPrompt, setAiPrompt] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showAiPanel, setShowAiPanel] = useState(false);

  // Fetch Data from Supabase
  const fetchData = async () => {
    // Keep space loading separate to not flicker on date change if spaces rarely change
    // But for simplicity we load all.
    setIsLoadingData(true);
    try {
        const { data: spacesData, error: spacesError } = await supabase.from('spaces').select('*').order('name');

        // Fetch bookings ONLY for selected date to optimize
        const { data: bookingsData, error: bookingsError } = await supabase
            .from('bookings')
            .select('*')
            .eq('date', selectedDate);

        if (spacesError) throw spacesError;
        if (bookingsError) throw bookingsError;

        const mappedSpaces = spacesData?.map((s: any) => ({
            id: s.id,
            name: s.name,
            type: s.type,
            capacity: s.capacity
        })) || [];

        const mappedBookings = bookingsData?.map((b: any) => ({
            id: b.id,
            spaceId: b.space_id,
            customerName: b.customer_name,
            serviceName: b.service_name,
            date: b.date,
            startTime: b.start_time,
            durationMinutes: b.duration_minutes,
            breakMinutes: b.break_minutes,
            status: b.status
        })) || [];

        setSpaces(mappedSpaces);
        setBookings(mappedBookings);

    } catch (error) {
        console.error("Supabase load error", error);
        // Fallback or empty state
        setSpaces([]);
        setBookings([]);
    } finally {
        setIsLoadingData(false);
    }
  };

  useEffect(() => {
      fetchData();
  }, [selectedDate]);

  // Handlers
  const handleSlotClick = (spaceId: string, time: string) => {
    setEditingBooking(null);
    setInitialFormState({ spaceId, startTime: time, durationMinutes: 60, date: selectedDate });
    setIsModalOpen(true);
  };

  const handleBookingClick = (booking: Booking) => {
    setEditingBooking(booking);
    setInitialFormState(booking);
    setIsModalOpen(true);
  };

  const handleFormSubmit = async (data: any) => {
    // Optimistic Update
    const tempId = Math.random().toString(36).substr(2, 9);
    const newBooking = { ...data, id: editingBooking ? editingBooking.id : tempId };

    // Prepare DB object (snake_case)
    const dbBooking = {
        space_id: data.spaceId,
        customer_name: data.customerName,
        service_name: data.serviceName,
        date: data.date,
        start_time: data.startTime,
        duration_minutes: data.durationMinutes,
        break_minutes: data.breakMinutes,
        status: data.status
    };

    // If date changed in form, we might need to remove it from current view if it doesn't match selectedDate
    const isSameDate = data.date === selectedDate;

    if (editingBooking) {
      if (isSameDate) {
          setBookings(prev => prev.map(b => b.id === editingBooking.id ? newBooking : b));
      } else {
          setBookings(prev => prev.filter(b => b.id !== editingBooking.id));
      }
      await supabase.from('bookings').update(dbBooking).eq('id', editingBooking.id);
    } else {
      if (isSameDate) {
          setBookings(prev => [...prev, newBooking]);
      }
      const { data: created, error } = await supabase.from('bookings').insert(dbBooking).select().single();
      if(created && isSameDate) {
          // Replace temp ID with real ID
          setBookings(prev => prev.map(b => b.id === tempId ? { ...newBooking, id: created.id } : b));
      }
    }

    // If we changed date, maybe we should refetch or just let the optimistic logic handle the view
    if (!isSameDate && !editingBooking) {
        // New booking on different date - nothing to show here.
    }

    setIsModalOpen(false);
    setEditingBooking(null);
  };

  // Space Management Handlers
  const handleAddSpace = async (space: Omit<Space, 'id'>) => {
      const { data, error } = await supabase.from('spaces').insert(space).select().single();
      if (data) {
          setSpaces(prev => [...prev, { ...space, id: data.id }]);
      }
  };

  const handleDeleteSpace = async (id: string) => {
      setSpaces(prev => prev.filter(s => s.id !== id)); // Optimistic
      await supabase.from('spaces').delete().eq('id', id);
  };

  // AI Handlers
  const handleAiAction = async () => {
    if (!aiPrompt.trim()) return;
    setIsAiLoading(true);
    setAiResponse('');

    if (aiPrompt.toLowerCase().includes('analyse') || aiPrompt.toLowerCase().includes('résumé')) {
        const sentiment = await analyzeDailySentiment(bookings);
        setAiResponse(sentiment);
    } else {
        const suggestion = await generateSmartScheduleSuggestion(aiPrompt, spaces, bookings);
        setAiResponse(suggestion);
    }
    setIsAiLoading(false);
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const changeDate = (days: number) => {
      const date = new Date(selectedDate);
      date.setDate(date.getDate() + days);
      setSelectedDate(date.toISOString().split('T')[0]);
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-800 font-sans overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col shadow-xl transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0
      `}>
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-teal-500 rounded-lg flex items-center justify-center">
