          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {spaces.map(space => {
          const isEditing = editingId === space.id;

          if (isEditing && editForm) {
              return (
