import React, { useState, useEffect } from 'react';
import { BookingStatus, Space, Booking } from '../types';
import { Button } from './Button';
import { Clock, Calendar as CalendarIcon, AlertTriangle, Users, Info, Trash2, ChevronRight, ChevronLeft, Check, User, MapPin } from 'lucide-react';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
  currentBookings: Booking[];
  onDelete?: () => void;
}

const STATUS_LABELS: Record<BookingStatus, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.MAINTENANCE]: 'Maintenance',
  [BookingStatus.BLOCKED]: 'Bloqué',
};

const timeToMins = (t: string) => {
    const [h, m] = t.split(':').map(Number);
    return h * 60 + m;
}

const STEPS = [
    { id: 1, title: 'Client & Service', icon: User },
    { id: 2, title: 'Lieu & Date', icon: MapPin },
    { id: 3, title: 'Détails & Validation', icon: Check },
];

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData, currentBookings, onDelete }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || spaces[0]?.id || '',
    date: initialData?.date || new Date().toISOString().split('T')[0],
    startTime: initialData?.startTime || '09:00',
    durationMinutes: initialData?.durationMinutes || 60,
    breakMinutes: initialData?.breakMinutes || 0,
    pax: initialData?.pax || 1,
    status: initialData?.status || BookingStatus.CONFIRMED,
  });

  const [capacityInfo, setCapacityInfo] = useState<{
      currentLoad: number;
      max: number;
      remaining: number;
      isOver: boolean;
  } | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  useEffect(() => {
    calculateCapacity();
  }, [formData.spaceId, formData.date, formData.startTime, formData.durationMinutes, formData.pax]);

  const calculateCapacity = () => {
      const space = spaces.find(s => s.id === formData.spaceId);
      if (!space) return;

      const newStart = timeToMins(formData.startTime);
      const newEnd = newStart + Number(formData.durationMinutes) + Number(formData.breakMinutes);

      // Filter concurrent bookings
      const concurrent = currentBookings.filter(b => {
          if (b.spaceId !== formData.spaceId) return false;
          if (b.date !== formData.date) return false;
          if (initialData && b.id === initialData.id) return false; // Exclude self if editing
          if (b.status === BookingStatus.CANCELED) return false;

          const bStart = timeToMins(b.startTime);
          const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);

          return (newStart < bEnd && newEnd > bStart);
      });

      // Sum pax of concurrent bookings
      const currentLoad = concurrent.reduce((sum, b) => sum + (b.pax || 1), 0);
      const newPax = Number(formData.pax);
      const totalLoad = currentLoad + newPax;

      setCapacityInfo({
          currentLoad,
          max: space.capacity,
          remaining: Math.max(0, space.capacity - currentLoad),
          isOver: totalLoad > space.capacity
      });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
        ...formData,
        durationMinutes: Number(formData.durationMinutes),
        breakMinutes: Number(formData.breakMinutes),
        pax: Number(formData.pax)
    });
  };

  const handleDelete = () => {
      if(window.confirm("Êtes-vous sûr de vouloir supprimer définitivement cette réservation ?")) {
          onDelete?.();
      }
  }

  const nextStep = () => {
      // Basic validation per step
      if (currentStep === 1) {
          if (!formData.customerName || !formData.serviceName) return; // Add visual feedback if needed
      }
      setCurrentStep(p => Math.min(STEPS.length, p + 1));
  };

  const prevStep = () => {
      setCurrentStep(p => Math.max(1, p - 1));
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col h-full">
      {/* Progress Bar */}
      <div className="mb-8 px-2">
          <div className="flex items-center justify-between relative">
              <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-slate-100 -z-10 rounded-full"></div>
              <div 
                className="absolute left-0 top-1/2 transform -translate-y-1/2 h-1 bg-teal-500 -z-10 rounded-full transition-all duration-300" 
                style={{ width: `${((currentStep - 1) / (STEPS.length - 1)) * 100}%` }}
              ></div>

              {STEPS.map((step) => {
                  const Icon = step.icon;
                  const isActive = step.id === currentStep;
                  const isCompleted = step.id < currentStep;

                  return (
                      <div key={step.id} className="flex flex-col items-center group">
                          <div className={`
                              w-10 h-10 rounded-full flex items-center justify-center border-4 transition-all duration-300 z-10
                              ${isActive ? 'bg-teal-600 border-teal-100 text-white shadow-lg scale-110' : 
                                isCompleted ? 'bg-teal-600 border-white text-white' : 'bg-white border-slate-200 text-slate-300'}
                          `}>
                              {isCompleted ? <Check size={18} /> : <Icon size={18} />}
                          </div>
                          <span className={`text-xs font-medium mt-2 transition-colors duration-300 ${isActive ? 'text-teal-700' : 'text-slate-400'}`}>
                              {step.title}
                          </span>
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="flex-1 overflow-y-auto px-1">
        {/* Step 1: Info Client */}
        {currentStep === 1 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-8 duration-300">
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Qui est le client ?</label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18}/>
                        <input
                            type="text"
                            name="customerName"
                            required
                            value={formData.customerName}
                            onChange={handleChange}
                            className="w-full rounded-lg border-slate-200 border py-3 pl-10 pr-4 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                            placeholder="Nom complet (ex: Jean Dupont)"
                            autoFocus
                        />
                    </div>
                </div>

                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Quel soin/service ?</label>
                    <input
                        type="text"
                        name="serviceName"
                        required
                        value={formData.serviceName}
                        onChange={handleChange}
                        className="w-full rounded-lg border-slate-200 border py-3 px-4 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                        placeholder="ex: Massage Suédois 1h"
                    />
                </div>
            </div>
        )}

        {/* Step 2: Date & Space */}
        {currentStep === 2 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-8 duration-300">
                 <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Choisir l'espace</label>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {spaces.map(space => (
                            <div 
                                key={space.id}
                                onClick={() => setFormData(prev => ({ ...prev, spaceId: space.id }))}
                                className={`cursor-pointer p-3 rounded-xl border transition-all ${formData.spaceId === space.id ? 'bg-teal-50 border-teal-500 shadow-md ring-1 ring-teal-500' : 'bg-white border-slate-200 hover:border-teal-300'}`}
                            >
                                <div className="font-medium text-sm text-slate-800">{space.name}</div>
                                <div className="text-xs text-slate-500 mt-1 flex justify-between">
                                    <span>{space.type}</span>
                                    <span>Max: {space.capacity}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Date</label>
                        <div className="relative">
                            <input
                                type="date"
                                name="date"
                                required
                                value={formData.date}
                                onChange={handleChange}
                                className="w-full rounded-lg border-slate-200 border p-3 pl-9 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                            />
                            <CalendarIcon size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Heure Début</label>
                        <div className="relative">
                             <input
                                type="time"
                                name="startTime"
                                required
                                value={formData.startTime}
                                onChange={handleChange}
                                className="w-full rounded-lg border-slate-200 border p-3 pl-9 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                            />
                            <Clock size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Step 3: Details & Confirmation */}
        {currentStep === 3 && (
            <div className="space-y-5 animate-in fade-in slide-in-from-right-8 duration-300">

                {/* Capacity Alert */}
                {capacityInfo && (
                    <div className={`p-4 rounded-xl text-sm border flex items-start gap-3 shadow-sm ${capacityInfo.isOver ? 'bg-red-50 border-red-200 text-red-700' : 'bg-blue-50 border-blue-200 text-blue-700'}`}>
                        {capacityInfo.isOver ? <AlertTriangle className="flex-shrink-0 mt-0.5" size={20} /> : <Info className="flex-shrink-0 mt-0.5" size={20} />}
                        <div>
                            <p className="font-bold text-base mb-1">
                                {capacityInfo.isOver ? "Attention : Surbooking !" : "Disponibilité OK"}
                            </p>
                            <p className="opacity-90">
                                {capacityInfo.currentLoad} personne(s) déjà prévue(s) sur ce créneau (Capacité Max: {capacityInfo.max}). 
                            </p>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">Durée (min)</label>
                        <input
                            type="number"
                            name="durationMinutes"
                            required
                            min="15"
                            step="5"
                            value={formData.durationMinutes}
                            onChange={handleChange}
                            className="w-full rounded-lg border-slate-200 border p-3 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">Nb. Personnes</label>
                        <div className="relative">
                            <input
                                type="number"
                                name="pax"
                                required
                                min="1"
                                value={formData.pax}
                                onChange={handleChange}
                                className="w-full rounded-lg border-slate-200 border p-3 pl-9 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm"
                            />
                            <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">Temps de pause</label>
                        <select
                            name="breakMinutes"
                            value={formData.breakMinutes}
                            onChange={handleChange}
                            className="w-full rounded-lg border-slate-200 border p-3 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm bg-white"
                        >
                            <option value="0">Aucun</option>
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="45">45 min</option>
                            <option value="60">1h</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">Statut</label>
                        <select
                            name="status"
                            value={formData.status}
                            onChange={handleChange}
                            className="w-full rounded-lg border-slate-200 border p-3 text-sm focus:border-teal-500 focus:ring-teal-500 shadow-sm bg-white"
                        >
                            {Object.values(BookingStatus).map(s => (
                            <option key={s} value={s}>{STATUS_LABELS[s]}</option>
                            ))}
                        </select>
                    </div>
                </div>
            </div>
        )}
      </div>

      <div className="pt-6 mt-4 border-t border-slate-100 flex items-center justify-between">

        {/* Left Side: Delete or Spacer */}
        <div>
            {onDelete ? (
                <Button type="button" variant="ghost" onClick={handleDelete} className="text-red-500 hover:text-red-700 hover:bg-red-50 px-3">
                    <Trash2 size={18} />
                </Button>
            ) : (
                <div className="w-10"></div>
            )}
        </div>

        {/* Right Side: Navigation */}
        <div className="flex gap-3">
            {currentStep > 1 ? (
                <Button type="button" variant="secondary" onClick={prevStep}>
                    <ChevronLeft size={18} className="mr-1" /> Retour
                </Button>
            ) : (
                <Button type="button" variant="secondary" onClick={onCancel}>
                    Annuler
                </Button>
            )}

            {currentStep < STEPS.length ? (
                <Button 
                    type="button" 
                    variant="primary" 
                    onClick={nextStep}
                    disabled={currentStep === 1 && (!formData.customerName || !formData.serviceName)}
                >
                    Suivant <ChevronRight size={18} className="ml-1" />
                </Button>
            ) : (
                <Button 
                    type="submit" 
                    variant={capacityInfo?.isOver ? "danger" : "primary"}
                    className="min-w-[120px]"
                >
                    {capacityInfo?.isOver ? "Forcer" : "Confirmer"}
                </Button>
            )}
        </div>
      </div>
    </form>
  );
};

import React, { useEffect, useRef } from 'react';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      document.body.style.overflow = 'hidden';
    }
    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 bg-slate-900/60 backdrop-blur-md transition-all duration-300">
      <div
        ref={modalRef}
        className="bg-white rounded-2xl shadow-[0_25px_50px_-12px_rgba(0,0,0,0.25)] w-full max-w-md overflow-hidden transform transition-all animate-in fade-in zoom-in-95 slide-in-from-bottom-2 duration-300 ring-1 ring-slate-900/5 flex flex-col max-h-[90vh]"
      >
        <div className="flex items-center justify-between px-6 py-5 bg-white z-10">
          <h3 className="text-xl font-bold text-slate-800 tracking-tight">{title}</h3>
          <button
            onClick={onClose}
            className="p-2 -mr-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-all"
            aria-label="Fermer"
          >
            <X size={20} />
          </button>
        </div>
        <div className="px-6 pb-6 overflow-y-auto flex-1 custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

