import React, { useRef, useMemo } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE } from '../constants';
import { Plus, Users, AlertCircle } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    if ((e.target as HTMLElement).closest('.booking-block')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="flex border-b border-slate-200 bg-slate-50/80 backdrop-blur-sm sticky top-0 z-20">
        <div className="w-40 md:w-56 flex-shrink-0 p-4 font-semibold text-slate-700 flex items-center border-r border-slate-200 text-sm md:text-base bg-slate-50">
          Espaces
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
            <div style={{ width: `${gridWidth}px` }} className="h-12 relative flex items-center">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute text-xs text-slate-400 font-medium transform -translate-x-1/2 flex flex-col items-center"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span>{hour}h</span>
                        <div className="h-1.5 w-px bg-slate-300 mt-1"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative">
        <div className="min-w-max">
            {spaces.map(space => {
                const spaceBookings = bookings.filter(b => b.spaceId === space.id && b.status !== BookingStatus.CANCELED);

                // --- Logic to calculate Full/Busy Zones ---
                // 1. Get all significant time points (start and end of bookings)
                const timePoints = new Set<number>();
                spaceBookings.forEach(b => {
                    const start = timeToMinutes(b.startTime);
                    const end = start + b.durationMinutes + (b.breakMinutes || 0);
                    timePoints.add(start);
                    timePoints.add(end);
                });

                // 2. Sort points to create time slices
                const sortedPoints = Array.from(timePoints).sort((a, b) => a - b);

                // 3. Analyze each slice
                const fullZones = [];
                for (let i = 0; i < sortedPoints.length - 1; i++) {
                    const p1 = sortedPoints[i];
                    const p2 = sortedPoints[i+1];
                    if (p2 <= p1) continue;

                    // Calculate total pax in this slice
                    // A booking is active if it starts before p2 AND ends after p1
                    const currentLoad = spaceBookings.reduce((sum, b) => {
                         const bStart = timeToMinutes(b.startTime);
                         const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);
                         if (bStart < p2 && bEnd > p1) {
                             return sum + (b.pax || 1);
                         }
                         return sum;
                    }, 0);

                    if (currentLoad >= space.capacity) {
                        fullZones.push({
                            start: p1,
                            end: p2,
                            load: currentLoad,
                            isOver: currentLoad > space.capacity
                        });
                    }
                }

                return (
                <div key={space.id} className="flex border-b border-slate-100 group hover:bg-slate-50 transition-colors min-h-[6rem]">
                    <div className="w-40 md:w-56 flex-shrink-0 p-3 border-r border-slate-200 bg-white sticky left-0 z-20 flex flex-col justify-center shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                        <div className="flex justify-between items-start">
                             <span className="font-semibold text-slate-700 text-sm truncate">{space.name}</span>
                             <div className="flex items-center text-slate-400 text-xs gap-1 bg-slate-100 px-1.5 py-0.5 rounded-full">
                                <Users size={10} /> {space.capacity}
                             </div>
                        </div>
                        <span className="text-[11px] text-slate-400 uppercase tracking-wider mt-1">{space.type}</span>
                    </div>

                    <div 
                        className="relative h-24 border-r border-slate-100 bg-[linear-gradient(90deg,transparent_29px,#f1f5f9_30px)] bg-[length:75px_100%]"
                        style={{ width: `${gridWidth}px` }}
                        onClick={(e) => handleGridClick(e, space.id)}
                    >
                        {/* Hour Vertical Lines */}
                        {timeMarkers.map(hour => (
                            <div 
                                key={`line-${hour}`} 
                                className="absolute top-0 bottom-0 border-l border-slate-100 border-dashed pointer-events-none"
                                style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                            />
                        ))}

                        {/* Full/Overload Zones Background Indicators */}
                        {fullZones.map((zone, idx) => {
                             const startMins = zone.start - (OPENING_HOUR * 60);
                             const duration = zone.end - zone.start;
                             const width = duration * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             return (
                                 <div
                                    key={`zone-${idx}`}
                                    className={`absolute top-0 bottom-0 pointer-events-none z-0 flex flex-col items-center justify-end pb-1 border-t-2 ${zone.isOver ? 'bg-red-100/40 border-red-500' : 'bg-orange-50/40 border-orange-400'}`}
                                    style={{
                                        left: `${left}px`,
                                        width: `${width}px`,
                                        backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 5px, rgba(255,255,255,0.5) 5px, rgba(255,255,255,0.5) 10px)'
                                    }}
                                 >
                                     <div className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full mb-auto mt-1 shadow-sm whitespace-nowrap z-10 ${zone.isOver ? 'bg-red-500 text-white' : 'bg-orange-400 text-white'}`}>
                                         {zone.isOver ? 'SURBOOKÉ' : 'COMPLET'} {zone.load}/{space.capacity}
                                     </div>
                                 </div>
                             );
                        })}

                        {/* Bookings */}
                        {spaceBookings.map((booking, index) => {
                             // Naive stacking logic
                             const myStart = timeToMinutes(booking.startTime);

                             // Visual Calculations
                             const startMins = myStart - (OPENING_HOUR * 60);
                             const width = booking.durationMinutes * PIXELS_PER_MINUTE;
                             const breakWidth = (booking.breakMinutes || 0) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             let bgClass = "bg-teal-100 border-teal-300 text-teal-900";
                             if (booking.status === BookingStatus.MAINTENANCE) bgClass = "bg-red-100 border-red-300 text-red-800";
                             if (booking.status === BookingStatus.PENDING) bgClass = "bg-amber-100 border-amber-300 text-amber-800";
                             if (booking.status === BookingStatus.BLOCKED) bgClass = "bg-slate-200 border-slate-400 text-slate-800";

                             // Improved Stacking for visibility over Full Zones
                             const laneIndex = index % Math.max(1, space.capacity);
                             const totalLanes = spaceBookings.filter(b => {
                                 const s = timeToMinutes(b.startTime);
                                 const e = s + b.durationMinutes + (b.breakMinutes || 0);
                                 const currentS = myStart;
                                 const currentE = myStart + booking.durationMinutes + (booking.breakMinutes || 0);
                                 return (s < currentE && e > currentS);
                             }).length; // Rough overlap count

                             // Adjust height to fit
                             const effectiveCapacity = Math.max(totalLanes, space.capacity);
                             const heightPercent = 85 / effectiveCapacity;
                             const topPercent = 5 + (index % effectiveCapacity) * (90 / effectiveCapacity);

                             return (
                                <React.Fragment key={booking.id}>
                                    <div
                                        style={{ 
                                            left: `${left}px`, 
                                            width: `${width}px`,
                                            top: `${topPercent}%`,
                                            height: `${heightPercent}%`,
                                            zIndex: 20 + index
                                        }}
                                        className={`booking-block absolute rounded border text-xs px-2 flex flex-col justify-center overflow-hidden whitespace-nowrap cursor-pointer hover:shadow-md hover:brightness-95 transition-all ${bgClass}`}
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onBookingClick(booking);
                                        }}
                                        title={`${booking.customerName} - ${booking.serviceName}`}
                                    >
                                        <div className="font-semibold truncate text-[11px] leading-tight flex justify-between items-center">
                                            <span>{booking.serviceName}</span>
                                            {booking.pax > 1 && <span className="text-[9px] bg-white/40 px-1 rounded flex items-center"><Users size={8} className="mr-0.5"/> {booking.pax}</span>}
                                        </div>
                                        {heightPercent > 30 && <div className="truncate opacity-80 text-[10px] hidden sm:block">{booking.customerName}</div>}
                                    </div>

                                    {booking.breakMinutes && booking.breakMinutes > 0 && (
                                        <div 
                                            className="absolute z-10 bg-slate-50 rounded-r border-y border-r border-slate-200/60"
                                            style={{
                                                left: `${left + width}px`,
                                                width: `${breakWidth}px`,
                                                top: `${topPercent}%`,
                                                height: `${heightPercent}%`,
                                                backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 2px, #cbd5e1 2px, #cbd5e1 4px)'
                                            }}
                                            title="Temps de pause / Nettoyage"
                                        />
                                    )}
                                </React.Fragment>
                            );
                        })}

                        {/* Hover Plus */}
                        <div className="absolute inset-0 opacity-0 group-hover:opacity-100 pointer-events-none flex items-center justify-center z-0">
                            <Plus className="text-slate-300 w-6 h-6" />
                        </div>
                    </div>
                </div>
                );
            })}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE } from '../constants';
import { Plus, Users, Clock, Info } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

// Helper to get color based on status
const getStatusColor = (status: BookingStatus) => {
    switch (status) {
        case BookingStatus.CONFIRMED: return 'teal';
        case BookingStatus.PENDING: return 'amber';
        case BookingStatus.MAINTENANCE: return 'red';
        case BookingStatus.BLOCKED: return 'slate';
        case BookingStatus.CANCELED: return 'gray';
        default: return 'teal';
    }
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  // Current time state
  const [currentTimePos, setCurrentTimePos] = useState<number | null>(null);

  useEffect(() => {
    const updateTime = () => {
        const now = new Date();
        const currentHour = now.getHours();
        const currentMin = now.getMinutes();

        // Only show if within opening hours
        if (currentHour >= OPENING_HOUR && currentHour < CLOSING_HOUR) {
            const minutesFromStart = ((currentHour - OPENING_HOUR) * 60) + currentMin;
            setCurrentTimePos(minutesFromStart * PIXELS_PER_MINUTE);
        } else {
            setCurrentTimePos(null);
        }
    };

    updateTime();
    const interval = setInterval(updateTime, 60000); // Update every minute
    return () => clearInterval(interval);
  }, []);

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    if ((e.target as HTMLElement).closest('.booking-card')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Sticky Header */}
      <div className="flex border-b border-slate-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="w-48 md:w-64 flex-shrink-0 p-4 font-bold text-slate-800 flex items-center border-r border-slate-200 bg-slate-50/50 backdrop-blur-md">
          <span className="text-lg">Espaces</span>
          <span className="ml-auto text-xs font-normal text-slate-400 bg-white px-2 py-1 rounded-full border border-slate-100">
            {spaces.length} salles
          </span>
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
            <div style={{ width: `${gridWidth}px` }} className="h-14 relative flex items-end pb-2">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute transform -translate-x-1/2 flex flex-col items-center group"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span className="text-xs font-semibold text-slate-400 group-hover:text-teal-600 transition-colors mb-1">{hour}h</span>
                        <div className="h-1.5 w-px bg-slate-200 group-hover:bg-teal-400 transition-colors"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative bg-slate-50/30">
        <div className="min-w-max relative">

            {/* Global Current Time Line (Overlay) */}
            {currentTimePos !== null && (
                <div 
                    className="absolute top-0 bottom-0 z-40 border-l-2 border-red-500 pointer-events-none"
                    style={{ left: `${256 + currentTimePos}px` /* 256px is roughly w-64 */ }} 
                >
                    <div className="absolute -top-1.5 -left-[5px] w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm" />
                    <div className="absolute top-2 left-1 bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded shadow-sm opacity-80">
                        Maintenant
                    </div>
                </div>
            )}

            {spaces.map(space => {
                const spaceBookings = bookings.filter(b => b.spaceId === space.id && b.status !== BookingStatus.CANCELED);

                // --- Logic to calculate Full/Busy Zones ---
                const timePoints = new Set<number>();
                spaceBookings.forEach(b => {
                    const start = timeToMinutes(b.startTime);
                    const end = start + b.durationMinutes + (b.breakMinutes || 0);
                    timePoints.add(start);
                    timePoints.add(end);
                });

                const sortedPoints = Array.from(timePoints).sort((a, b) => a - b);
                const fullZones = [];
                for (let i = 0; i < sortedPoints.length - 1; i++) {
                    const p1 = sortedPoints[i];
                    const p2 = sortedPoints[i+1];
                    if (p2 <= p1) continue;

                    const currentLoad = spaceBookings.reduce((sum, b) => {
                         const bStart = timeToMinutes(b.startTime);
                         const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);
                         if (bStart < p2 && bEnd > p1) return sum + (b.pax || 1);
                         return sum;
                    }, 0);

                    if (currentLoad >= space.capacity) {
                        fullZones.push({
                            start: p1,
                            end: p2,
                            load: currentLoad,
                            isOver: currentLoad > space.capacity
                        });
                    }
                }

                return (
                <div key={space.id} className="flex border-b border-slate-100 group min-h-[7rem] hover:bg-white transition-colors">
                    {/* Space Column */}
                    <div className="w-48 md:w-64 flex-shrink-0 p-4 border-r border-slate-200 bg-white sticky left-0 z-20 flex flex-col justify-center shadow-[4px_0_10px_-4px_rgba(0,0,0,0.05)]">
                        <div className="flex justify-between items-start mb-1">
                             <span className="font-bold text-slate-700 text-sm truncate pr-2">{space.name}</span>
                             <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wide border ${
                                 space.type === 'MASSAGE' ? 'bg-purple-50 text-purple-700 border-purple-100' :
                                 space.type === 'POOL' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                                 'bg-slate-50 text-slate-600 border-slate-100'
                             }`}>
                                 {space.type}
                             </span>
                        </div>
                        <div className="flex items-center text-slate-400 text-xs mt-1">
                            <Users size={12} className="mr-1.5" /> 
                            <span>Capacité: <strong className="text-slate-600">{space.capacity}</strong> pers.</span>
                        </div>
                    </div>

                    {/* Time Grid for this Space */}
                    <div 
                        className="relative border-r border-slate-100 flex-1 bg-white"
                        style={{ width: `${gridWidth}px` }}
                        onClick={(e) => handleGridClick(e, space.id)}
                    >
                        {/* Vertical Guidelines */}
                        {timeMarkers.map(hour => (
                            <div 
                                key={`line-${hour}`} 
                                className="absolute top-0 bottom-0 border-l border-slate-100/60 pointer-events-none"
                                style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                            />
                        ))}

                        {/* Full/Overload Zones (Subtle Background) */}
                        {fullZones.map((zone, idx) => {
                             const startMins = zone.start - (OPENING_HOUR * 60);
                             const width = (zone.end - zone.start) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             return (
                                 <div
                                    key={`zone-${idx}`}
                                    className={`absolute top-1 bottom-1 pointer-events-none z-0 flex items-center justify-center rounded-sm transition-all
                                        ${zone.isOver ? 'bg-red-50' : 'bg-slate-100'}`}
                                    style={{
                                        left: `${left}px`,
                                        width: `${width}px`,
                                        // Subtle stripe pattern via CSS radial/linear gradient simulation
                                        backgroundImage: 'linear-gradient(45deg, rgba(0,0,0,0.02) 25%, transparent 25%, transparent 50%, rgba(0,0,0,0.02) 50%, rgba(0,0,0,0.02) 75%, transparent 75%, transparent)',
                                        backgroundSize: '8px 8px'
                                    }}
                                 >
                                     <div className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded border shadow-sm ${
                                         zone.isOver ? 'bg-white text-red-600 border-red-100' : 'bg-white text-slate-400 border-slate-200'
                                     }`}>
                                         {zone.isOver ? 'Surbooké' : 'Complet'}
                                     </div>
                                 </div>
                             );
                        })}

                        {/* Booking Cards */}
                        {spaceBookings.map((booking, index) => {
                             const myStart = timeToMinutes(booking.startTime);
                             const startMins = myStart - (OPENING_HOUR * 60);
                             const width = booking.durationMinutes * PIXELS_PER_MINUTE;
                             const breakWidth = (booking.breakMinutes || 0) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             // Color logic
                             const colorName = getStatusColor(booking.status);
                             const borderClass = `border-${colorName}-500`;
                             const textClass = `text-${colorName}-900`;

                             // Stacking Logic
                             const laneIndex = index % Math.max(1, space.capacity);
                             const effectiveCapacity = Math.max(1, space.capacity); // Simplified stacking for cleaner look

                             // Card layout variables
                             const topPercent = 5 + (index % effectiveCapacity) * (90 / effectiveCapacity);
                             const heightPercent = 85 / effectiveCapacity;

                             return (
                                <React.Fragment key={booking.id}>
                                    <div
                                        style={{ 
                                            left: `${left}px`, 
                                            width: `${width}px`,
                                            top: `${topPercent}%`,
                                            height: `${heightPercent}%`,
                                            zIndex: 20 + index
                                        }}
                                        className={`booking-card absolute flex flex-col justify-center px-3 py-1 cursor-pointer transition-all duration-200
                                            bg-white border border-slate-200 border-l-4 rounded-r-md shadow-sm hover:shadow-md hover:scale-[1.01] hover:z-30
                                            ${borderClass} overflow-hidden group/card`}
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onBookingClick(booking);
                                        }}
                                    >
                                        <div className="flex items-center justify-between gap-2">
                                            <span className={`font-bold text-xs truncate ${textClass}`}>{booking.serviceName}</span>
                                            {booking.pax > 1 && (
                                                <div className="flex items-center bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded-full text-[9px] flex-shrink-0">
                                                    <Users size={8} className="mr-0.5" /> {booking.pax}
                                                </div>
                                            )}
                                        </div>
                                        {/* Hide details if slot is too small vertically */}
                                        {heightPercent > 30 && width > 60 && (
                                            <div className="text-[10px] text-slate-500 truncate mt-0.5 flex items-center gap-1">
                                                <span className="font-medium">{booking.customerName}</span>
                                                <span className="text-slate-300">•</span>
                                                <span>{booking.startTime} - {minutesToTime(timeToMinutes(booking.startTime) + booking.durationMinutes)}</span>
                                            </div>
                                        )}

                                        {/* Hover Tooltip (Simple browser title for now, or could be a custom component) */}
                                        <div className="hidden group-hover/card:block absolute inset-0 bg-white/50 backdrop-blur-[1px] flex items-center justify-center font-semibold text-xs text-slate-800 opacity-0 group-hover/card:opacity-100 transition-opacity">
                                            Voir détails
                                        </div>
                                    </div>

                                    {/* Break / Cleaning Time */}
                                    {booking.breakMinutes && booking.breakMinutes > 0 && (
                                        <div 
                                            className="absolute z-10 bg-slate-50 rounded-r border-y border-r border-slate-200/50 flex items-center justify-center"
                                            style={{
                                                left: `${left + width}px`,
                                                width: `${breakWidth}px`,
                                                top: `${topPercent + 10}%`, // Slightly smaller height
                                                height: `${heightPercent - 20}%`,
                                                backgroundImage: 'linear-gradient(135deg, #cbd5e1 25%, transparent 25%, transparent 50%, #cbd5e1 50%, #cbd5e1 75%, transparent 75%, transparent)',
                                                backgroundSize: '4px 4px'
                                            }}
                                            title="Temps de pause / Nettoyage"
                                        >
                                            <Clock size={10} className="text-slate-400 opacity-50" />
                                        </div>
                                    )}
                                </React.Fragment>
                            );
                        })}

                        {/* Hover Interaction Layer */}
                        <div className="absolute inset-0 opacity-0 hover:opacity-100 pointer-events-none z-10">
                            <div className="h-full w-px bg-teal-500/30 absolute top-0 bottom-0 shadow-[0_0_10px_rgba(20,184,166,0.3)] hidden group-hover:block" 
                                 style={{ left: 'var(--mouse-x, 0px)' }} />
                        </div>

                        {/* Add Button Placeholder (visible on hover over empty space) */}
                        <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none flex items-center justify-center">
                             {/* This could be a floating '+' following cursor, but kept simple for now */}
                        </div>
                    </div>
                </div>
                );
            })}
        </div>
      </div>

      {/* Legend Footer */}
      <div className="bg-white border-t border-slate-200 p-2 px-6 flex items-center gap-6 text-[10px] text-slate-500 uppercase tracking-wider font-semibold">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-teal-500"></div> Confirmé</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-amber-500"></div> En attente</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> Maintenance</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-slate-100 border border-slate-300"></div> Complet</div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BookingStatus, Space, Booking } from '../types';
import { Button } from './Button';
import { Calendar as CalendarIcon, AlertTriangle, Users, Trash2, ChevronRight, Check, User, MapPin, ArrowRight } from 'lucide-react';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
  currentBookings: Booking[];
  onDelete?: () => void;
}

const STATUS_LABELS: Record<BookingStatus, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.MAINTENANCE]: 'Maintenance',
  [BookingStatus.BLOCKED]: 'Bloqué',
};

// Helper functions for time conversion
const timeToMins = (t: string) => {
    if (!t) return 0;
    const [h, m] = t.split(':').map(Number);
    return h * 60 + m;
};

const minsToTime = (m: number) => {
    const h = Math.floor(m / 60);
    const min = m % 60;
    return `${h.toString().padStart(2, '0')}:${min.toString().padStart(2, '0')}`;
};

const STEPS = [
    { id: 1, title: 'Client', icon: User },
    { id: 2, title: 'Créneau', icon: MapPin },
    { id: 3, title: 'Validation', icon: Check },
];

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData, currentBookings, onDelete }) => {
  const [currentStep, setCurrentStep] = useState(1);

  // Initialize form state
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || (spaces.length > 0 ? spaces[0].id : ''),
    date: initialData?.date || new Date().toISOString().split('T')[0],
    startTime: initialData?.startTime || '09:00',
    endTime: '', // Calculated via useEffect on mount
    durationMinutes: initialData?.durationMinutes || 60,
    breakMinutes: initialData?.breakMinutes || 0,
    pax: initialData?.pax || 1,
    status: initialData?.status || BookingStatus.CONFIRMED,
  });

  // Calculate initial EndTime if not present or on load
  useEffect(() => {
    const startMins = timeToMins(formData.startTime);
    const endMins = startMins + Number(formData.durationMinutes);
    setFormData(prev => ({ ...prev, endTime: minsToTime(endMins) }));
  }, []); // Run once on mount

  const [capacityInfo, setCapacityInfo] = useState<{
      currentLoad: number;
      max: number;
      remaining: number;
      isOver: boolean;
  } | null>(null);

  // --- Handlers for synchronized time fields ---

  const handleStartTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newStart = e.target.value;
      const startMins = timeToMins(newStart);
      const endMins = startMins + Number(formData.durationMinutes);
      setFormData(prev => ({
          ...prev,
          startTime: newStart,
          endTime: minsToTime(endMins)
      }));
  };

  const handleEndTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newEnd = e.target.value;
      const endMins = timeToMins(newEnd);
      const startMins = timeToMins(formData.startTime);

      let duration = endMins - startMins;
      // Force minimum duration of 15 mins to avoid issues
      if (duration < 15) duration = 15; 

      setFormData(prev => ({
          ...prev,
          endTime: newEnd,
          durationMinutes: duration
      }));
  };

  const handleDurationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const duration = Number(e.target.value);
      const startMins = timeToMins(formData.startTime);
      const endMins = startMins + duration;

      setFormData(prev => ({
          ...prev,
          durationMinutes: duration,
          endTime: minsToTime(endMins)
      }));
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // --- Capacity Calculation ---
  useEffect(() => {
    try {
        calculateCapacity();
    } catch (e) {
        console.error("Error calculating capacity", e);
    }
  }, [formData.spaceId, formData.date, formData.startTime, formData.durationMinutes, formData.pax]);

  const calculateCapacity = () => {
      if (!formData.spaceId) return;
      const space = spaces.find(s => s.id === formData.spaceId);
      if (!space) return;

      const newStart = timeToMins(formData.startTime);
      const newEnd = newStart + Number(formData.durationMinutes) + Number(formData.breakMinutes);

      const concurrent = currentBookings.filter(b => {
          if (b.spaceId !== formData.spaceId) return false;
          if (b.date !== formData.date) return false;
          if (initialData && b.id === initialData.id) return false;
          if (b.status === BookingStatus.CANCELED) return false;

          const bStart = timeToMins(b.startTime);
          const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);

          return (newStart < bEnd && newEnd > bStart);
      });

      const currentLoad = concurrent.reduce((sum, b) => sum + (b.pax || 1), 0);
      const newPax = Number(formData.pax);
      const totalLoad = currentLoad + newPax;

      setCapacityInfo({
          currentLoad,
          max: space.capacity,
          remaining: Math.max(0, space.capacity - currentLoad),
          isOver: totalLoad > space.capacity
      });
  };

  // Manual Trigger for Submission to prevent ghost submissions
  const triggerSubmit = () => {
    onSubmit({
        ...formData,
        serviceName: formData.serviceName || 'Réservation', // Default if empty
        durationMinutes: Number(formData.durationMinutes),
        breakMinutes: Number(formData.breakMinutes),
        pax: Number(formData.pax)
    });
  };

  const handleDelete = () => {
      if(window.confirm("Supprimer cette réservation ?")) {
          onDelete?.();
      }
  }

  const nextStep = () => {
      if (currentStep === 1) {
          if (!formData.customerName) return; // Only customerName is required
      }
      if (currentStep === 2) {
          if (!formData.spaceId) {
             alert("Veuillez sélectionner un espace.");
             return;
          }
      }
      setCurrentStep(p => Math.min(STEPS.length, p + 1));
  };

  const prevStep = () => {
      setCurrentStep(p => Math.max(1, p - 1));
  };

  // Robust Enter key handling
  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
          e.preventDefault(); // Always prevent default form submit
          // Only allow navigation on earlier steps
          if (currentStep < STEPS.length) {
             nextStep();
          }
          // On last step, do nothing. User must click confirm.
      }
  };

  if (spaces.length === 0) {
      return (
          <div className="text-center py-8 text-slate-500">
              <p>Aucun espace configuré.</p>
              <p className="text-sm mt-2">Veuillez créer des espaces dans les paramètres.</p>
              <Button variant="secondary" onClick={onCancel} className="mt-4">Fermer</Button>
          </div>
      );
  }

  return (
    <form 
        onSubmit={(e) => e.preventDefault()} 
        onKeyDown={handleKeyDown} 
        className="flex flex-col h-full"
        autoComplete="off"
    >
      {/* Compact Progress Bar - Added pt-5 to prevent top clipping */}
      <div className="mb-8 px-4 pt-5">
          <div className="flex items-center justify-between relative">
              <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-0.5 bg-slate-100 -z-10 rounded-full"></div>
              <div 
                className="absolute left-0 top-1/2 transform -translate-y-1/2 h-0.5 bg-teal-500 -z-10 rounded-full transition-all duration-300" 
                style={{ width: `${((currentStep - 1) / (STEPS.length - 1)) * 100}%` }}
              ></div>

              {STEPS.map((step) => {
                  const Icon = step.icon;
                  const isActive = step.id === currentStep;
                  const isCompleted = step.id < currentStep;

                  return (
                      <div key={step.id} className="flex flex-col items-center relative group">
                          <div className={`
                              w-8 h-8 rounded-full flex items-center justify-center border-2 transition-all duration-300 z-10
                              ${isActive ? 'bg-teal-600 border-teal-600 text-white shadow-lg shadow-teal-200 scale-125' : 
                                isCompleted ? 'bg-teal-600 border-teal-600 text-white' : 'bg-white border-slate-200 text-slate-300'}
                          `}>
                              {isCompleted ? <Check size={14} /> : <Icon size={14} />}
                          </div>
                          <div className={`absolute -bottom-6 left-1/2 transform -translate-x-1/2 whitespace-nowrap text-[10px] font-bold uppercase tracking-wider transition-colors duration-300 ${isActive ? 'text-teal-700' : 'text-slate-300'}`}>
                             {step.title}
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="flex-1 min-h-[320px]">
        {/* Step 1: Info Client */}
        {currentStep === 1 && (
            <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="group">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Client</label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-teal-500 transition-colors" size={18}/>
                        <input
                            type="text"
                            name="customerName"
                            required
                            value={formData.customerName}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 pl-10 pr-4 text-sm transition-all"
                            placeholder="Nom complet"
                            autoFocus
                        />
                    </div>
                </div>

                <div className="group">
                    <div className="flex justify-between items-center mb-1.5 ml-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">Prestation</label>
                        <span className="text-[10px] text-slate-400 italic font-medium">Optionnel</span>
                    </div>
                    <input
                        type="text"
                        name="serviceName"
                        value={formData.serviceName}
                        onChange={handleChange}
                        className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 px-4 text-sm transition-all"
                        placeholder="Ex: Massage, Soin visage..."
                    />
                </div>
            </div>
        )}

        {/* Step 2: Date, Space & Times */}
        {currentStep === 2 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Espace</label>
                    <div className="grid grid-cols-2 gap-2 max-h-32 overflow-y-auto pr-1 custom-scrollbar">
                        {spaces.map(space => (
                            <div 
                                key={space.id}
                                onClick={() => setFormData(prev => ({ ...prev, spaceId: space.id }))}
                                className={`cursor-pointer px-3 py-2 rounded-lg border-2 transition-all ${formData.spaceId === space.id ? 'bg-teal-50/50 border-teal-500' : 'bg-slate-50 border-transparent hover:bg-slate-100'}`}
                            >
                                <div className={`font-semibold text-xs ${formData.spaceId === space.id ? 'text-teal-900' : 'text-slate-700'}`}>{space.name}</div>
                                <div className="text-[10px] text-slate-500 mt-0.5">{space.type}</div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                     <div className="group">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Date</label>
                        <div className="relative">
                            <input
                                type="date"
                                name="date"
                                required
                                value={formData.date}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-2 text-sm transition-all"
                            />
                            <CalendarIcon size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                    <div>
                         {/* Linked Duration Field */}
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Durée (min)</label>
                         <input
                            type="number"
                            name="durationMinutes"
                            required
                            min="15"
                            step="5"
                            value={formData.durationMinutes}
                            onChange={handleDurationChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm font-medium"
                        />
                    </div>
                </div>

                {/* Time Range with End Time */}
                <div className="flex items-center gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex-1">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Début</label>
                        <input
                            type="time"
                            name="startTime"
                            required
                            value={formData.startTime}
                            onChange={handleStartTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                    <ArrowRight size={20} className="text-slate-300" />
                    <div className="flex-1 text-right">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Fin</label>
                        <input
                            type="time"
                            name="endTime"
                            required
                            value={formData.endTime}
                            onChange={handleEndTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0 text-right"
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Step 3: Details & Confirmation */}
        {currentStep === 3 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">

                {capacityInfo && (
                    <div className={`p-3 rounded-lg text-xs border flex items-center gap-3 ${capacityInfo.isOver ? 'bg-red-50 border-red-100 text-red-700' : 'bg-emerald-50 border-emerald-100 text-emerald-700'}`}>
                        {capacityInfo.isOver ? <AlertTriangle className="flex-shrink-0" size={18} /> : <Check className="flex-shrink-0" size={18} />}
                        <div>
                            <span className="font-bold block">{capacityInfo.isOver ? "Surbooking !" : "Créneau disponible"}</span>
                            <span className="opacity-80">Charge: {capacityInfo.currentLoad}/{capacityInfo.max} pers.</span>
                        </div>
                    </div>
                )}

                <div className="bg-slate-50 rounded-xl p-3 border border-slate-100 flex justify-between items-center text-sm">
                    <span className="text-slate-500">Horaire prévu</span>
                    <span className="font-bold text-slate-800">{formData.startTime} - {formData.endTime} ({formData.durationMinutes} min)</span>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Personnes</label>
                        <div className="relative">
                            <input
                                type="number"
                                name="pax"
                                required
                                min="1"
                                value={formData.pax}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-3 text-sm"
                            />
                            <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Pause (Nettoyage)</label>
                        <select
                            name="breakMinutes"
                            value={formData.breakMinutes}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                        >
                            <option value="0">Aucune</option>
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="60">1h</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Statut</label>
                    <select
                        name="status"
                        value={formData.status}
                        onChange={handleChange}
                        className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                    >
                        {Object.values(BookingStatus).map(s => (
                        <option key={s} value={s}>{STATUS_LABELS[s]}</option>
                        ))}
                    </select>
                </div>
            </div>
        )}
      </div>

      <div className="pt-4 mt-2 flex items-center justify-between">

        {/* Left Side: Delete */}
        <div>
            {onDelete && (
                <button type="button" onClick={handleDelete} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50" title="Supprimer">
                    <Trash2 size={18} />
                </button>
            )}
        </div>

        {/* Right Side: Navigation */}
        <div className="flex gap-2">
            {currentStep === 1 ? (
                <Button type="button" variant="ghost" onClick={onCancel} className="text-slate-500">
                    Annuler
                </Button>
            ) : (
                <Button type="button" variant="secondary" onClick={prevStep}>
                    Retour
                </Button>
            )}

            {currentStep < STEPS.length ? (
                <Button 
                    type="button" 
                    variant="primary" 
                    onClick={nextStep}
                    disabled={currentStep === 1 && !formData.customerName}
                    className="pl-5 pr-4"
                >
                    Suivant <ChevronRight size={16} className="ml-1" />
                </Button>
            ) : (
                <Button 
                    type="button" // Changed to explicit button type to prevent form submit race conditions
                    onClick={triggerSubmit}
                    variant={capacityInfo?.isOver ? "danger" : "primary"}
                    className="shadow-lg shadow-teal-500/30"
                >
                    {capacityInfo?.isOver ? "Forcer" : "Confirmer"}
                </Button>
            )}
        </div>
      </div>
    </form>
  );
};

export enum BookingStatus {
  CONFIRMED = 'CONFIRMED',
  PENDING = 'PENDING',
  CANCELED = 'CANCELED',
  MAINTENANCE = 'MAINTENANCE',
  BLOCKED = 'BLOCKED',
  CHECKED_IN = 'CHECKED_IN',
  NO_SHOW = 'NO_SHOW'
}

export interface Space {
  id: string;
  name: string;
  type: 'SAUNA' | 'MASSAGE' | 'POOL' | 'RELAX' | 'HAMMAM' | 'SPA' | string;
  capacity: number;
}

export interface Booking {
  id: string;
  spaceId: string;
  customerName: string;
  serviceName: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:mm format
  durationMinutes: number;
  breakMinutes?: number; 
  pax: number; // Number of people
  status: BookingStatus;
  notes?: string;
  isPaid: boolean;
}

export interface TimeSlot {
  time: string; // HH:mm
  display: string;
}

export interface DailyStats {
  occupancyRate: number;
  totalBookings: number;
}

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Booking, BookingStatus } from '../types';
import { Users, CalendarCheck, Activity, UserX, CheckCircle } from 'lucide-react';

interface DashboardProps {
  bookings: Booking[];
}

const COLORS = ['#0d9488', '#f59e0b', '#ef4444', '#64748b', '#10b981', '#1e293b'];

const STATUS_LABELS: Record<string, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.MAINTENANCE]: 'Maint.',
  [BookingStatus.BLOCKED]: 'Bloqué',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.CHECKED_IN]: 'Présent',
  [BookingStatus.NO_SHOW]: 'No-Show'
};

export const Dashboard: React.FC<DashboardProps> = ({ bookings }) => {
  const stats = useMemo(() => {
    const total = bookings.length;
    const confirmed = bookings.filter(b => b.status === BookingStatus.CONFIRMED || b.status === BookingStatus.CHECKED_IN).length;
    const noShows = bookings.filter(b => b.status === BookingStatus.NO_SHOW).length;
    const occupancy = Math.round((bookings.reduce((acc, curr) => acc + curr.durationMinutes, 0) / (12 * 60 * 6)) * 100);

    return { total, confirmed, noShows, occupancy };
  }, [bookings]);

  const typeData = useMemo(() => {
     const counts: Record<string, number> = {};
     bookings.forEach(b => {
         counts[b.status] = (counts[b.status] || 0) + 1;
     });
     return Object.keys(counts).map(key => ({ name: STATUS_LABELS[key] || key, value: counts[key] }));
  }, [bookings]);

  const timeDistribution = useMemo(() => {
      const dist = Array(12).fill(0).map((_, i) => ({ hour: `${8 + i}h`, count: 0 }));
      bookings.forEach(b => {
          const hour = parseInt(b.startTime.split(':')[0]);
          if (hour >= 8 && hour < 20) {
              dist[hour - 8].count += 1;
          }
      });
      return dist;
  }, [bookings]);

  const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between transition-transform hover:scale-[1.02]">
      <div>
        <p className="text-sm text-slate-500 font-medium mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
      </div>
      <div className={`p-3 rounded-full ${color} bg-opacity-10`}>
        <Icon size={24} className={color.replace('bg-', 'text-')} />
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Réservations" value={stats.total} icon={CalendarCheck} color="bg-blue-500" />
        <StatCard title="Présents / Confirmés" value={stats.confirmed} icon={CheckCircle} color="bg-teal-500" />
        <StatCard title="No-Shows" value={stats.noShows} icon={UserX} color="bg-slate-500" />
        <StatCard title="Taux d'occupation" value={`${stats.occupancy}%`} icon={Activity} color="bg-orange-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Répartition par Statut</h4>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={typeData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {typeData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex flex-wrap justify-center gap-x-4 gap-y-2 mt-4 text-sm text-slate-600">
              {typeData.map((entry, index) => (
                  <div key={entry.name} className="flex items-center gap-2">
                      <span className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[index % COLORS.length]}}></span>
                      {entry.name}
                  </div>
              ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Activité Horaire</h4>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={timeDistribution}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="hour" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                <Bar dataKey="count" fill="#0d9488" radius={[4, 4, 0, 0]} name="Réservations" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Space, Booking, BookingStatus } from '../types';
import { OPENING_HOUR, CLOSING_HOUR, PIXELS_PER_MINUTE } from '../constants';
import { Plus, Users, Clock, Info } from 'lucide-react';

interface PlanningGridProps {
  spaces: Space[];
  bookings: Booking[];
  onSlotClick: (spaceId: string, time: string) => void;
  onBookingClick: (booking: Booking) => void;
}

const timeToMinutes = (time: string): number => {
  const [hours, mins] = time.split(':').map(Number);
  return hours * 60 + mins;
};

const minutesToTime = (minutes: number): string => {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

// Helper to get color based on status
const getStatusColor = (status: BookingStatus) => {
    switch (status) {
        case BookingStatus.CONFIRMED: return 'teal';
        case BookingStatus.CHECKED_IN: return 'emerald'; // Distinct green for checked in
        case BookingStatus.PENDING: return 'amber';
        case BookingStatus.MAINTENANCE: return 'red';
        case BookingStatus.BLOCKED: return 'slate';
        case BookingStatus.NO_SHOW: return 'zinc'; // Dark grey/black for no-show
        case BookingStatus.CANCELED: return 'gray';
        default: return 'teal';
    }
};

export const PlanningGrid: React.FC<PlanningGridProps> = ({ spaces, bookings, onSlotClick, onBookingClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const totalMinutes = (CLOSING_HOUR - OPENING_HOUR) * 60;
  const gridWidth = totalMinutes * PIXELS_PER_MINUTE;

  // Current time state
  const [currentTimePos, setCurrentTimePos] = useState<number | null>(null);

  useEffect(() => {
    const updateTime = () => {
        const now = new Date();
        const currentHour = now.getHours();
        const currentMin = now.getMinutes();

        // Only show if within opening hours
        if (currentHour >= OPENING_HOUR && currentHour < CLOSING_HOUR) {
            const minutesFromStart = ((currentHour - OPENING_HOUR) * 60) + currentMin;
            setCurrentTimePos(minutesFromStart * PIXELS_PER_MINUTE);
        } else {
            setCurrentTimePos(null);
        }
    };

    updateTime();
    const interval = setInterval(updateTime, 60000); // Update every minute
    return () => clearInterval(interval);
  }, []);

  const timeMarkers = [];
  for (let h = OPENING_HOUR; h <= CLOSING_HOUR; h++) {
    timeMarkers.push(h);
  }

  const handleGridClick = (e: React.MouseEvent, spaceId: string) => {
    if ((e.target as HTMLElement).closest('.booking-card')) return;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clickX = e.clientX - rect.left + (scrollRef.current?.scrollLeft || 0);

    const rawMins = clickX / PIXELS_PER_MINUTE;
    const snappedMins = Math.round(rawMins / 15) * 15;
    const actualMins = (OPENING_HOUR * 60) + snappedMins;

    onSlotClick(spaceId, minutesToTime(actualMins));
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Sticky Header */}
      <div className="flex border-b border-slate-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="w-48 md:w-64 flex-shrink-0 p-4 font-bold text-slate-800 flex items-center border-r border-slate-200 bg-slate-50/50 backdrop-blur-md">
          <span className="text-lg">Espaces</span>
          <span className="ml-auto text-xs font-normal text-slate-400 bg-white px-2 py-1 rounded-full border border-slate-100">
            {spaces.length} salles
          </span>
        </div>
        <div className="flex-1 overflow-hidden relative" ref={scrollRef}>
            <div style={{ width: `${gridWidth}px` }} className="h-14 relative flex items-end pb-2">
                {timeMarkers.map(hour => (
                    <div 
                        key={hour} 
                        className="absolute transform -translate-x-1/2 flex flex-col items-center group"
                        style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                    >
                        <span className="text-xs font-semibold text-slate-400 group-hover:text-teal-600 transition-colors mb-1">{hour}h</span>
                        <div className="h-1.5 w-px bg-slate-200 group-hover:bg-teal-400 transition-colors"></div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto overflow-x-auto hide-scrollbar relative bg-slate-50/30">
        <div className="min-w-max relative">

            {/* Global Current Time Line (Overlay) */}
            {currentTimePos !== null && (
                <div 
                    className="absolute top-0 bottom-0 z-40 border-l-2 border-red-500 pointer-events-none"
                    style={{ left: `${256 + currentTimePos}px` /* 256px is roughly w-64 */ }} 
                >
                    <div className="absolute -top-1.5 -left-[5px] w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm" />
                    <div className="absolute top-2 left-1 bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded shadow-sm opacity-80">
                        Maintenant
                    </div>
                </div>
            )}

            {spaces.map(space => {
                const spaceBookings = bookings.filter(b => b.spaceId === space.id && b.status !== BookingStatus.CANCELED);

                // --- Logic to calculate Full/Busy Zones ---
                const timePoints = new Set<number>();
                spaceBookings.forEach(b => {
                    const start = timeToMinutes(b.startTime);
                    const end = start + b.durationMinutes + (b.breakMinutes || 0);
                    timePoints.add(start);
                    timePoints.add(end);
                });

                const sortedPoints = Array.from(timePoints).sort((a, b) => a - b);
                const fullZones = [];
                for (let i = 0; i < sortedPoints.length - 1; i++) {
                    const p1 = sortedPoints[i];
                    const p2 = sortedPoints[i+1];
                    if (p2 <= p1) continue;

                    const currentLoad = spaceBookings.reduce((sum, b) => {
                         const bStart = timeToMinutes(b.startTime);
                         const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);
                         if (bStart < p2 && bEnd > p1) return sum + (b.pax || 1);
                         return sum;
                    }, 0);

                    if (currentLoad >= space.capacity) {
                        fullZones.push({
                            start: p1,
                            end: p2,
                            load: currentLoad,
                            isOver: currentLoad > space.capacity
                        });
                    }
                }

                return (
                <div key={space.id} className="flex border-b border-slate-100 group min-h-[7rem] hover:bg-white transition-colors">
                    {/* Space Column */}
                    <div className="w-48 md:w-64 flex-shrink-0 p-4 border-r border-slate-200 bg-white sticky left-0 z-20 flex flex-col justify-center shadow-[4px_0_10px_-4px_rgba(0,0,0,0.05)]">
                        <div className="flex justify-between items-start mb-1">
                             <span className="font-bold text-slate-700 text-sm truncate pr-2">{space.name}</span>
                             <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wide border ${
                                 space.type === 'MASSAGE' ? 'bg-purple-50 text-purple-700 border-purple-100' :
                                 space.type === 'POOL' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                                 'bg-slate-50 text-slate-600 border-slate-100'
                             }`}>
                                 {space.type}
                             </span>
                        </div>
                        <div className="flex items-center text-slate-400 text-xs mt-1">
                            <Users size={12} className="mr-1.5" /> 
                            <span>Capacité: <strong className="text-slate-600">{space.capacity}</strong> pers.</span>
                        </div>
                    </div>

                    {/* Time Grid for this Space */}
                    <div 
                        className="relative border-r border-slate-100 flex-1 bg-white"
                        style={{ width: `${gridWidth}px` }}
                        onClick={(e) => handleGridClick(e, space.id)}
                    >
                        {/* Vertical Guidelines */}
                        {timeMarkers.map(hour => (
                            <div 
                                key={`line-${hour}`} 
                                className="absolute top-0 bottom-0 border-l border-slate-100/60 pointer-events-none"
                                style={{ left: `${(hour - OPENING_HOUR) * 60 * PIXELS_PER_MINUTE}px` }}
                            />
                        ))}

                        {/* Full/Overload Zones (Subtle Background) */}
                        {fullZones.map((zone, idx) => {
                             const startMins = zone.start - (OPENING_HOUR * 60);
                             const width = (zone.end - zone.start) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             return (
                                 <div
                                    key={`zone-${idx}`}
                                    className={`absolute top-1 bottom-1 pointer-events-none z-0 flex items-center justify-center rounded-sm transition-all
                                        ${zone.isOver ? 'bg-red-50' : 'bg-slate-100'}`}
                                    style={{
                                        left: `${left}px`,
                                        width: `${width}px`,
                                        // Subtle stripe pattern via CSS radial/linear gradient simulation
                                        backgroundImage: 'linear-gradient(45deg, rgba(0,0,0,0.02) 25%, transparent 25%, transparent 50%, rgba(0,0,0,0.02) 50%, rgba(0,0,0,0.02) 75%, transparent 75%, transparent)',
                                        backgroundSize: '8px 8px'
                                    }}
                                 >
                                     <div className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded border shadow-sm ${
                                         zone.isOver ? 'bg-white text-red-600 border-red-100' : 'bg-white text-slate-400 border-slate-200'
                                     }`}>
                                         {zone.isOver ? 'Surbooké' : 'Complet'}
                                     </div>
                                 </div>
                             );
                        })}

                        {/* Booking Cards */}
                        {spaceBookings.map((booking, index) => {
                             const myStart = timeToMinutes(booking.startTime);
                             const startMins = myStart - (OPENING_HOUR * 60);
                             const width = booking.durationMinutes * PIXELS_PER_MINUTE;
                             const breakWidth = (booking.breakMinutes || 0) * PIXELS_PER_MINUTE;
                             const left = startMins * PIXELS_PER_MINUTE;

                             // Color logic
                             const colorName = getStatusColor(booking.status);
                             const borderClass = `border-${colorName}-500`;
                             const textClass = `text-${colorName}-900`;
                             const bgClass = booking.status === BookingStatus.NO_SHOW ? 'bg-zinc-100' : 'bg-white';

                             // Stacking Logic
                             const laneIndex = index % Math.max(1, space.capacity);
                             const effectiveCapacity = Math.max(1, space.capacity); // Simplified stacking for cleaner look

                             // Card layout variables
                             const topPercent = 5 + (index % effectiveCapacity) * (90 / effectiveCapacity);
                             const heightPercent = 85 / effectiveCapacity;

                             return (
                                <React.Fragment key={booking.id}>
                                    <div
                                        style={{ 
                                            left: `${left}px`, 
                                            width: `${width}px`,
                                            top: `${topPercent}%`,
                                            height: `${heightPercent}%`,
                                            zIndex: 20 + index
                                        }}
                                        className={`booking-card absolute flex flex-col justify-center px-3 py-1 cursor-pointer transition-all duration-200
                                            ${bgClass} border border-slate-200 border-l-4 rounded-r-md shadow-sm hover:shadow-md hover:scale-[1.01] hover:z-30
                                            ${borderClass} overflow-hidden group/card`}
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onBookingClick(booking);
                                        }}
                                    >
                                        <div className="flex items-center justify-between gap-2">
                                            <span className={`font-bold text-xs truncate ${textClass} ${booking.status === BookingStatus.NO_SHOW ? 'line-through opacity-70' : ''}`}>{booking.serviceName}</span>
                                            {booking.pax > 1 && (
                                                <div className="flex items-center bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded-full text-[9px] flex-shrink-0">
                                                    <Users size={8} className="mr-0.5" /> {booking.pax}
                                                </div>
                                            )}
                                        </div>
                                        {/* Hide details if slot is too small vertically */}
                                        {heightPercent > 30 && width > 60 && (
                                            <div className="text-[10px] text-slate-500 truncate mt-0.5 flex items-center gap-1">
                                                <span className="font-medium">{booking.customerName}</span>
                                                <span className="text-slate-300">•</span>
                                                <span>{booking.startTime} - {minutesToTime(timeToMinutes(booking.startTime) + booking.durationMinutes)}</span>
                                            </div>
                                        )}

                                        {/* Hover Tooltip (Simple browser title for now, or could be a custom component) */}
                                        <div className="hidden group-hover/card:block absolute inset-0 bg-white/50 backdrop-blur-[1px] flex items-center justify-center font-semibold text-xs text-slate-800 opacity-0 group-hover/card:opacity-100 transition-opacity">
                                            Voir détails
                                        </div>
                                    </div>

                                    {/* Break / Cleaning Time */}
                                    {booking.breakMinutes && booking.breakMinutes > 0 && (
                                        <div 
                                            className="absolute z-10 bg-slate-50 rounded-r border-y border-r border-slate-200/50 flex items-center justify-center"
                                            style={{
                                                left: `${left + width}px`,
                                                width: `${breakWidth}px`,
                                                top: `${topPercent + 10}%`, // Slightly smaller height
                                                height: `${heightPercent - 20}%`,
                                                backgroundImage: 'linear-gradient(135deg, #cbd5e1 25%, transparent 25%, transparent 50%, #cbd5e1 50%, #cbd5e1 75%, transparent 75%, transparent)',
                                                backgroundSize: '4px 4px'
                                            }}
                                            title="Temps de pause / Nettoyage"
                                        >
                                            <Clock size={10} className="text-slate-400 opacity-50" />
                                        </div>
                                    )}
                                </React.Fragment>
                            );
                        })}

                        {/* Hover Interaction Layer */}
                        <div className="absolute inset-0 opacity-0 hover:opacity-100 pointer-events-none z-10">
                            <div className="h-full w-px bg-teal-500/30 absolute top-0 bottom-0 shadow-[0_0_10px_rgba(20,184,166,0.3)] hidden group-hover:block" 
                                 style={{ left: 'var(--mouse-x, 0px)' }} />
                        </div>
                    </div>
                </div>
                );
            })}
        </div>
      </div>

      {/* Legend Footer */}
      <div className="bg-white border-t border-slate-200 p-2 px-6 flex items-center gap-6 text-[10px] text-slate-500 uppercase tracking-wider font-semibold">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-teal-500"></div> Confirmé</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500"></div> Présent</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-zinc-500"></div> No-Show</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-amber-500"></div> En attente</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> Maintenance</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-slate-100 border border-slate-300"></div> Complet</div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BookingStatus, Space, Booking } from '../types';
import { Button } from './Button';
import { Calendar as CalendarIcon, AlertTriangle, Users, Trash2, ChevronRight, Check, User, MapPin, ArrowRight, DollarSign, UserCheck, UserX } from 'lucide-react';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
  currentBookings: Booking[];
  onDelete?: () => void;
}

const STATUS_LABELS: Record<BookingStatus, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.MAINTENANCE]: 'Maintenance',
  [BookingStatus.BLOCKED]: 'Bloqué',
  [BookingStatus.CHECKED_IN]: 'Présent',
  [BookingStatus.NO_SHOW]: 'No-Show'
};

// Helper functions for time conversion
const timeToMins = (t: string) => {
    if (!t) return 0;
    const [h, m] = t.split(':').map(Number);
    return h * 60 + m;
};

const minsToTime = (m: number) => {
    const h = Math.floor(m / 60);
    const min = m % 60;
    return `${h.toString().padStart(2, '0')}:${min.toString().padStart(2, '0')}`;
};

const STEPS = [
    { id: 1, title: 'Client', icon: User },
    { id: 2, title: 'Créneau', icon: MapPin },
    { id: 3, title: 'Validation', icon: Check },
];

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData, currentBookings, onDelete }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const isEditing = !!initialData?.id;

  // Initialize form state
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || (spaces.length > 0 ? spaces[0].id : ''),
    date: initialData?.date || new Date().toISOString().split('T')[0],
    startTime: initialData?.startTime || '09:00',
    endTime: '', // Calculated via useEffect on mount
    durationMinutes: initialData?.durationMinutes || 60,
    breakMinutes: initialData?.breakMinutes || 0,
    pax: initialData?.pax || 1,
    status: initialData?.status || BookingStatus.CONFIRMED,
    isPaid: initialData?.isPaid || false,
  });

  // Calculate initial EndTime if not present or on load
  useEffect(() => {
    const startMins = timeToMins(formData.startTime);
    const endMins = startMins + Number(formData.durationMinutes);
    setFormData(prev => ({ ...prev, endTime: minsToTime(endMins) }));
  }, []); // Run once on mount

  const [capacityInfo, setCapacityInfo] = useState<{
      currentLoad: number;
      max: number;
      remaining: number;
      isOver: boolean;
  } | null>(null);

  // --- Handlers for synchronized time fields ---

  const handleStartTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newStart = e.target.value;
      const startMins = timeToMins(newStart);
      const endMins = startMins + Number(formData.durationMinutes);
      setFormData(prev => ({
          ...prev,
          startTime: newStart,
          endTime: minsToTime(endMins)
      }));
  };

  const handleEndTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newEnd = e.target.value;
      const endMins = timeToMins(newEnd);
      const startMins = timeToMins(formData.startTime);

      let duration = endMins - startMins;
      // Force minimum duration of 15 mins to avoid issues
      if (duration < 15) duration = 15; 

      setFormData(prev => ({
          ...prev,
          endTime: newEnd,
          durationMinutes: duration
      }));
  };

  const handleDurationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const duration = Number(e.target.value);
      const startMins = timeToMins(formData.startTime);
      const endMins = startMins + duration;

      setFormData(prev => ({
          ...prev,
          durationMinutes: duration,
          endTime: minsToTime(endMins)
      }));
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const togglePayment = () => {
      setFormData(prev => ({ ...prev, isPaid: !prev.isPaid }));
  };

  const setStatus = (status: BookingStatus) => {
      setFormData(prev => ({ ...prev, status }));
  };

  // --- Capacity Calculation ---
  useEffect(() => {
    try {
        calculateCapacity();
    } catch (e) {
        console.error("Error calculating capacity", e);
    }
  }, [formData.spaceId, formData.date, formData.startTime, formData.durationMinutes, formData.pax]);

  const calculateCapacity = () => {
      if (!formData.spaceId) return;
      const space = spaces.find(s => s.id === formData.spaceId);
      if (!space) return;

      const newStart = timeToMins(formData.startTime);
      const newEnd = newStart + Number(formData.durationMinutes) + Number(formData.breakMinutes);

      const concurrent = currentBookings.filter(b => {
          if (b.spaceId !== formData.spaceId) return false;
          if (b.date !== formData.date) return false;
          if (initialData && b.id === initialData.id) return false;
          if (b.status === BookingStatus.CANCELED) return false;

          const bStart = timeToMins(b.startTime);
          const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);

          return (newStart < bEnd && newEnd > bStart);
      });

      const currentLoad = concurrent.reduce((sum, b) => sum + (b.pax || 1), 0);
      const newPax = Number(formData.pax);
      const totalLoad = currentLoad + newPax;

      setCapacityInfo({
          currentLoad,
          max: space.capacity,
          remaining: Math.max(0, space.capacity - currentLoad),
          isOver: totalLoad > space.capacity
      });
  };

  // Manual Trigger for Submission to prevent ghost submissions
  const triggerSubmit = () => {
    onSubmit({
        ...formData,
        serviceName: formData.serviceName || 'Réservation', // Default if empty
        durationMinutes: Number(formData.durationMinutes),
        breakMinutes: Number(formData.breakMinutes),
        pax: Number(formData.pax)
    });
  };

  const handleDelete = () => {
      if(window.confirm("Supprimer cette réservation ?")) {
          onDelete?.();
      }
  }

  const nextStep = () => {
      if (currentStep === 1) {
          if (!formData.customerName) return; // Only customerName is required
      }
      if (currentStep === 2) {
          if (!formData.spaceId) {
             alert("Veuillez sélectionner un espace.");
             return;
          }
      }
      setCurrentStep(p => Math.min(STEPS.length, p + 1));
  };

  const prevStep = () => {
      setCurrentStep(p => Math.max(1, p - 1));
  };

  // Robust Enter key handling
  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
          e.preventDefault(); // Always prevent default form submit
          // Only allow navigation on earlier steps
          if (currentStep < STEPS.length) {
             nextStep();
          }
          // On last step, do nothing. User must click confirm.
      }
  };

  if (spaces.length === 0) {
      return (
          <div className="text-center py-8 text-slate-500">
              <p>Aucun espace configuré.</p>
              <p className="text-sm mt-2">Veuillez créer des espaces dans les paramètres.</p>
              <Button variant="secondary" onClick={onCancel} className="mt-4">Fermer</Button>
          </div>
      );
  }

  return (
    <form 
        onSubmit={(e) => e.preventDefault()} 
        onKeyDown={handleKeyDown} 
        className="flex flex-col h-full"
        autoComplete="off"
    >
      {/* Compact Progress Bar - Added pt-5 to prevent top clipping */}
      <div className="mb-8 px-4 pt-5">
          <div className="flex items-center justify-between relative">
              <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-0.5 bg-slate-100 -z-10 rounded-full"></div>
              <div 
                className="absolute left-0 top-1/2 transform -translate-y-1/2 h-0.5 bg-teal-500 -z-10 rounded-full transition-all duration-300" 
                style={{ width: `${((currentStep - 1) / (STEPS.length - 1)) * 100}%` }}
              ></div>

              {STEPS.map((step) => {
                  const Icon = step.icon;
                  const isActive = step.id === currentStep;
                  const isCompleted = step.id < currentStep;

                  return (
                      <div key={step.id} className="flex flex-col items-center relative group">
                          <div className={`
                              w-8 h-8 rounded-full flex items-center justify-center border-2 transition-all duration-300 z-10
                              ${isActive ? 'bg-teal-600 border-teal-600 text-white shadow-lg shadow-teal-200 scale-125' : 
                                isCompleted ? 'bg-teal-600 border-teal-600 text-white' : 'bg-white border-slate-200 text-slate-300'}
                          `}>
                              {isCompleted ? <Check size={14} /> : <Icon size={14} />}
                          </div>
                          <div className={`absolute -bottom-6 left-1/2 transform -translate-x-1/2 whitespace-nowrap text-[10px] font-bold uppercase tracking-wider transition-colors duration-300 ${isActive ? 'text-teal-700' : 'text-slate-300'}`}>
                             {step.title}
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="flex-1 min-h-[320px]">
        {/* Step 1: Info Client */}
        {currentStep === 1 && (
            <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="group">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Client</label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-teal-500 transition-colors" size={18}/>
                        <input
                            type="text"
                            name="customerName"
                            required
                            value={formData.customerName}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 pl-10 pr-4 text-sm transition-all"
                            placeholder="Nom complet"
                            autoFocus
                        />
                    </div>
                </div>

                <div className="group">
                    <div className="flex justify-between items-center mb-1.5 ml-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">Prestation</label>
                        <span className="text-[10px] text-slate-400 italic font-medium">Optionnel</span>
                    </div>
                    <input
                        type="text"
                        name="serviceName"
                        value={formData.serviceName}
                        onChange={handleChange}
                        className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 px-4 text-sm transition-all"
                        placeholder="Ex: Massage, Soin visage..."
                    />
                </div>
            </div>
        )}

        {/* Step 2: Date, Space & Times */}
        {currentStep === 2 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Espace</label>
                    <div className="grid grid-cols-2 gap-2 max-h-32 overflow-y-auto pr-1 custom-scrollbar">
                        {spaces.map(space => (
                            <div 
                                key={space.id}
                                onClick={() => setFormData(prev => ({ ...prev, spaceId: space.id }))}
                                className={`cursor-pointer px-3 py-2 rounded-lg border-2 transition-all ${formData.spaceId === space.id ? 'bg-teal-50/50 border-teal-500' : 'bg-slate-50 border-transparent hover:bg-slate-100'}`}
                            >
                                <div className={`font-semibold text-xs ${formData.spaceId === space.id ? 'text-teal-900' : 'text-slate-700'}`}>{space.name}</div>
                                <div className="text-[10px] text-slate-500 mt-0.5">{space.type}</div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                     <div className="group">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Date</label>
                        <div className="relative">
                            <input
                                type="date"
                                name="date"
                                required
                                value={formData.date}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-2 text-sm transition-all"
                            />
                            <CalendarIcon size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                    <div>
                         {/* Linked Duration Field */}
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Durée (min)</label>
                         <input
                            type="number"
                            name="durationMinutes"
                            required
                            min="15"
                            step="5"
                            value={formData.durationMinutes}
                            onChange={handleDurationChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm font-medium"
                        />
                    </div>
                </div>

                {/* Time Range with End Time */}
                <div className="flex items-center gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex-1">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Début</label>
                        <input
                            type="time"
                            name="startTime"
                            required
                            value={formData.startTime}
                            onChange={handleStartTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                    <ArrowRight size={20} className="text-slate-300" />
                    <div className="flex-1 text-right">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Fin</label>
                        <input
                            type="time"
                            name="endTime"
                            required
                            value={formData.endTime}
                            onChange={handleEndTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0 text-right"
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Step 3: Details & Confirmation */}
        {currentStep === 3 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">

                {/* Attendance Quick Actions (Only when editing) */}
                {isEditing && (
                    <div className="grid grid-cols-2 gap-3 mb-2">
                        <button 
                            type="button"
                            onClick={() => setStatus(BookingStatus.CHECKED_IN)}
                            className={`flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${formData.status === BookingStatus.CHECKED_IN ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                        >
                            <UserCheck size={18} /> Présent
                        </button>
                        <button 
                            type="button"
                            onClick={() => setStatus(BookingStatus.NO_SHOW)}
                            className={`flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${formData.status === BookingStatus.NO_SHOW ? 'bg-zinc-100 border-zinc-500 text-zinc-800 font-bold' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                        >
                            <UserX size={18} /> No-Show
                        </button>
                    </div>
                )}

                {/* Capacity Alert */}
                {capacityInfo && (
                    <div className={`p-3 rounded-lg text-xs border flex items-center gap-3 ${capacityInfo.isOver ? 'bg-red-50 border-red-100 text-red-700' : 'bg-emerald-50 border-emerald-100 text-emerald-700'}`}>
                        {capacityInfo.isOver ? <AlertTriangle className="flex-shrink-0" size={18} /> : <Check className="flex-shrink-0" size={18} />}
                        <div>
                            <span className="font-bold block">{capacityInfo.isOver ? "Surbooking !" : "Créneau disponible"}</span>
                            <span className="opacity-80">Charge: {capacityInfo.currentLoad}/{capacityInfo.max} pers.</span>
                        </div>
                    </div>
                )}

                {/* Info Row */}
                <div className="bg-slate-50 rounded-xl p-3 border border-slate-100 flex justify-between items-center text-sm">
                    <span className="text-slate-500">Horaire prévu</span>
                    <span className="font-bold text-slate-800">{formData.startTime} - {formData.endTime} ({formData.durationMinutes} min)</span>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Personnes</label>
                        <div className="relative">
                            <input
                                type="number"
                                name="pax"
                                required
                                min="1"
                                value={formData.pax}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-3 text-sm"
                            />
                            <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Pause (Nettoyage)</label>
                        <select
                            name="breakMinutes"
                            value={formData.breakMinutes}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                        >
                            <option value="0">Aucune</option>
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="60">1h</option>
                        </select>
                    </div>
                </div>

                {/* Status & Payment Row */}
                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Statut</label>
                        <select
                            name="status"
                            value={formData.status}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                        >
                            {Object.values(BookingStatus).map(s => (
                            <option key={s} value={s}>{STATUS_LABELS[s]}</option>
                            ))}
                        </select>
                    </div>

                    {/* Payment Toggle */}
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Paiement</label>
                        <button
                            type="button"
                            onClick={togglePayment}
                            className={`w-full rounded-xl border-2 flex items-center justify-between px-3 py-2.5 transition-all ${formData.isPaid ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                        >
                            <span className="text-sm font-medium">{formData.isPaid ? 'Payé' : 'Non Payé'}</span>
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center ${formData.isPaid ? 'bg-emerald-500 text-white' : 'bg-slate-200'}`}>
                                <DollarSign size={12} />
                            </div>
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <div className="pt-4 mt-2 flex items-center justify-between">

        {/* Left Side: Delete */}
        <div>
            {onDelete && (
                <button type="button" onClick={handleDelete} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50" title="Supprimer">
                    <Trash2 size={18} />
                </button>
            )}
        </div>

        {/* Right Side: Navigation */}
        <div className="flex gap-2">
            {currentStep === 1 ? (
                <Button type="button" variant="ghost" onClick={onCancel} className="text-slate-500">
                    Annuler
                </Button>
            ) : (
                <Button type="button" variant="secondary" onClick={prevStep}>
                    Retour
                </Button>
            )}

            {currentStep < STEPS.length ? (
                <Button 
                    type="button" 
                    variant="primary" 
                    onClick={nextStep}
                    disabled={currentStep === 1 && !formData.customerName}
                    className="pl-5 pr-4"
                >
                    Suivant <ChevronRight size={16} className="ml-1" />
                </Button>
            ) : (
                <Button 
                    type="button" // Changed to explicit button type to prevent form submit race conditions
                    onClick={triggerSubmit}
                    variant={capacityInfo?.isOver ? "danger" : "primary"}
                    className="shadow-lg shadow-teal-500/30"
                >
                    {capacityInfo?.isOver ? "Forcer" : "Confirmer"}
                </Button>
            )}
        </div>
      </div>
    </form>
  );
};

import React, { useState, useEffect } from 'react';
import { Calendar, LayoutDashboard, Settings, Plus, Search, Menu, X, Loader2, ChevronLeft, ChevronRight } from 'lucide-react';
import { Space, Booking } from './types';
import { PlanningGrid } from './components/PlanningGrid';
import { Dashboard } from './components/Dashboard';
import { Modal } from './components/Modal';
import { BookingForm } from './components/BookingForm';
import { Button } from './components/Button';
import { SpaceManager } from './components/SpaceManager';
import { supabase } from './supabaseClient';

enum View {
  DASHBOARD = 'DASHBOARD',
  CALENDAR = 'CALENDAR',
  SETTINGS = 'SETTINGS',
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.CALENDAR);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Data State
  const [spaces, setSpaces] = useState<Space[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(true);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [initialFormState, setInitialFormState] = useState<any>(null);

  // Fetch Data from Supabase
  const fetchData = async () => {
    setIsLoadingData(true);
    try {
        const { data: spacesData, error: spacesError } = await supabase.from('spaces').select('*').order('name');

        // Fetch bookings ONLY for selected date to optimize
        const { data: bookingsData, error: bookingsError } = await supabase
            .from('bookings')
            .select('*')
            .eq('date', selectedDate);

        if (spacesError) throw spacesError;
        if (bookingsError) throw bookingsError;

        const mappedSpaces = spacesData?.map((s: any) => ({
            id: s.id,
            name: s.name,
            type: s.type,
            capacity: s.capacity
        })) || [];

        const mappedBookings = bookingsData?.map((b: any) => ({
            id: b.id,
            spaceId: b.space_id,
            customerName: b.customer_name,
            serviceName: b.service_name,
            date: b.date,
            startTime: b.start_time,
            durationMinutes: b.duration_minutes,
            breakMinutes: b.break_minutes,
            pax: b.pax || 1,
            status: b.status,
            isPaid: b.is_paid || false
        })) || [];

        setSpaces(mappedSpaces);
        setBookings(mappedBookings);

    } catch (error) {
        console.error("Supabase load error", error);
        setSpaces([]);
        setBookings([]);
    } finally {
        setIsLoadingData(false);
    }
  };

  useEffect(() => {
      fetchData();
  }, [selectedDate]);

  // Handlers
  const handleSlotClick = (spaceId: string, time: string) => {
    setEditingBooking(null);
    setInitialFormState({ spaceId, startTime: time, durationMinutes: 60, date: selectedDate, pax: 1 });
    setIsModalOpen(true);
  };

  const handleBookingClick = (booking: Booking) => {
    setEditingBooking(booking);
    setInitialFormState(booking);
    setIsModalOpen(true);
  };

  const handleFormSubmit = async (data: any) => {
    // Optimistic Update
    const tempId = Math.random().toString(36).substr(2, 9);
    const newBooking = { ...data, id: editingBooking ? editingBooking.id : tempId };

    // Prepare DB object (snake_case)
    const dbBooking = {
        space_id: data.spaceId,
        customer_name: data.customerName,
        service_name: data.serviceName,
        date: data.date,
        start_time: data.startTime,
        duration_minutes: data.durationMinutes,
        break_minutes: data.breakMinutes,
        pax: data.pax,
        status: data.status,
        is_paid: data.isPaid
    };

    const isSameDate = data.date === selectedDate;

    if (editingBooking) {
      if (isSameDate) {
          setBookings(prev => prev.map(b => b.id === editingBooking.id ? newBooking : b));
      } else {
          setBookings(prev => prev.filter(b => b.id !== editingBooking.id));
      }
      await supabase.from('bookings').update(dbBooking).eq('id', editingBooking.id);
    } else {
      if (isSameDate) {
          setBookings(prev => [...prev, newBooking]);
      }
      const { data: created, error } = await supabase.from('bookings').insert(dbBooking).select().single();
      if(created && isSameDate) {
          setBookings(prev => prev.map(b => b.id === tempId ? { ...newBooking, id: created.id } : b));
      }
    }

    setIsModalOpen(false);
    setEditingBooking(null);
  };

  const handleDeleteBooking = async (id: string) => {
      setBookings(prev => prev.filter(b => b.id !== id));
      await supabase.from('bookings').delete().eq('id', id);
      setIsModalOpen(false);
  };

  const handleAddSpace = async (space: Omit<Space, 'id'>) => {
      const { data, error } = await supabase.from('spaces').insert(space).select().single();
      if (data) {
          setSpaces(prev => [...prev, { ...space, id: data.id }]);
      }
  };

  const handleUpdateSpace = async (space: Space) => {
      setSpaces(prev => prev.map(s => s.id === space.id ? space : s));
      await supabase.from('spaces').update({
          name: space.name,
          type: space.type,
          capacity: space.capacity
      }).eq('id', space.id);
  };

  const handleDeleteSpace = async (id: string) => {
      setSpaces(prev => prev.filter(s => s.id !== id));
      await supabase.from('spaces').delete().eq('id', id);
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const changeDate = (days: number) => {
      const date = new Date(selectedDate);
      date.setDate(date.getDate() + days);
      setSelectedDate(date.toISOString().split('T')[0]);
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-800 font-sans overflow-hidden">

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col shadow-xl transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0
      `}>
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center overflow-hidden">
                  <img 
                    src="https://www.inrap.fr/sites/inrap.fr/files/styles/article/public/thumbnails/image/logo-theleme2.jpg?itok=4U43jUPR" 
                    alt="Logo" 
                    className="w-full h-full object-cover"
                  />
              </div>
              <span className="font-bold text-lg tracking-tight">ZenSpace</span>
            </div>
            <button onClick={toggleSidebar} className="md:hidden text-slate-400 hover:text-white">
              <X size={20} />
            </button>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => { setCurrentView(View.CALENDAR); setIsSidebarOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.CALENDAR ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Calendar size={20} />
            <span className="font-medium">Planning</span>
          </button>

          <button 
             onClick={() => { setCurrentView(View.DASHBOARD); setIsSidebarOpen(false); }}
             className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.DASHBOARD ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            <span className="font-medium">Tableau de bord</span>
          </button>

          <button 
             onClick={() => { setCurrentView(View.SETTINGS); setIsSidebarOpen(false); }}
             className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${currentView === View.SETTINGS ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings size={20} />
            <span className="font-medium">Paramètres</span>
          </button>
        </nav>
      </aside>

      <main className="flex-1 flex flex-col relative overflow-hidden w-full">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-6 flex-shrink-0 z-20">
          <div className="flex items-center gap-3">
            <button onClick={toggleSidebar} className="md:hidden text-slate-500 hover:text-slate-700">
              <Menu size={24} />
            </button>
            <div className="flex flex-col md:flex-row md:items-center md:gap-4">
                 <h2 className="text-lg font-bold text-slate-800 hidden md:block">
                    {currentView === View.CALENDAR && 'Planning'}
                    {currentView === View.DASHBOARD && 'Vue d\'ensemble'}
                    {currentView === View.SETTINGS && 'Configuration'}
                </h2>
                {currentView !== View.SETTINGS && (
                    <div className="flex items-center bg-slate-100 rounded-lg p-1">
                        <button onClick={() => changeDate(-1)} className="p-1 hover:bg-white rounded-md text-slate-500 transition-all"><ChevronLeft size={16}/></button>
                        <input 
                            type="date" 
                            value={selectedDate} 
                            onChange={(e) => setSelectedDate(e.target.value)}
                            className="bg-transparent border-none text-xs md:text-sm font-medium text-slate-700 px-2 outline-none w-28 md:w-auto"
                        />
                        <button onClick={() => changeDate(1)} className="p-1 hover:bg-white rounded-md text-slate-500 transition-all"><ChevronRight size={16}/></button>
                    </div>
                )}
            </div>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative hidden lg:block">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
                <input type="text" placeholder="Rechercher..." className="pl-10 pr-4 py-2 bg-slate-100 rounded-full text-sm border-transparent focus:bg-white focus:ring-2 focus:ring-teal-500 transition-all outline-none w-48 lg:w-64" />
            </div>
            {currentView === View.CALENDAR && (
                <Button onClick={() => { setEditingBooking(null); setInitialFormState({date: selectedDate, startTime: '09:00', durationMinutes: 60, pax: 1}); setIsModalOpen(true); }} className="whitespace-nowrap">
                    <Plus size={18} className="md:mr-2" /> 
                    <span className="hidden md:inline">Réserver</span>
                </Button>
            )}
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 md:p-6 bg-slate-50/50 relative">
          {isLoadingData ? (
             <div className="absolute inset-0 flex items-center justify-center bg-white/50 backdrop-blur-sm z-30">
                 <Loader2 className="animate-spin text-teal-600 w-10 h-10" />
             </div>
          ) : (
            <>
                {currentView === View.CALENDAR && (
                    <PlanningGrid 
                        spaces={spaces} 
                        bookings={bookings} 
                        onSlotClick={handleSlotClick} 
                        onBookingClick={handleBookingClick}
                    />
                )}
                {currentView === View.DASHBOARD && (
                    <Dashboard bookings={bookings} />
                )}
                {currentView === View.SETTINGS && (
                    <SpaceManager 
                        spaces={spaces} 
                        onAddSpace={handleAddSpace}
                        onUpdateSpace={handleUpdateSpace}
                        onDeleteSpace={handleDeleteSpace}
                    />
                )}
            </>
          )}
        </div>
      </main>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={editingBooking ? "Modifier Réservation" : "Nouvelle Réservation"}
      >
        <BookingForm
            spaces={spaces}
            onSubmit={handleFormSubmit}
            onCancel={() => setIsModalOpen(false)}
            initialData={initialFormState}
            currentBookings={bookings}
            onDelete={editingBooking ? () => handleDeleteBooking(editingBooking.id) : undefined}
        />
      </Modal>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BookingStatus, Space, Booking } from '../types';
import { Button } from './Button';
import { Calendar as CalendarIcon, AlertTriangle, Users, Trash2, ChevronRight, Check, User, MapPin, ArrowRight, CreditCard, UserCheck, UserX } from 'lucide-react';

interface BookingFormProps {
  spaces: Space[];
  onSubmit: (data: any) => void;
  onCancel: () => void;
  initialData?: any;
  currentBookings: Booking[];
  onDelete?: () => void;
}

const STATUS_LABELS: Record<BookingStatus, string> = {
  [BookingStatus.CONFIRMED]: 'Confirmé',
  [BookingStatus.PENDING]: 'En attente',
  [BookingStatus.CANCELED]: 'Annulé',
  [BookingStatus.MAINTENANCE]: 'Maintenance',
  [BookingStatus.BLOCKED]: 'Bloqué',
  [BookingStatus.CHECKED_IN]: 'Présent',
  [BookingStatus.NO_SHOW]: 'No-Show'
};

// Helper functions for time conversion
const timeToMins = (t: string) => {
    if (!t) return 0;
    const [h, m] = t.split(':').map(Number);
    return h * 60 + m;
};

const minsToTime = (m: number) => {
    const h = Math.floor(m / 60);
    const min = m % 60;
    return `${h.toString().padStart(2, '0')}:${min.toString().padStart(2, '0')}`;
};

const STEPS = [
    { id: 1, title: 'Client', icon: User },
    { id: 2, title: 'Créneau', icon: MapPin },
    { id: 3, title: 'Validation', icon: Check },
];

export const BookingForm: React.FC<BookingFormProps> = ({ spaces, onSubmit, onCancel, initialData, currentBookings, onDelete }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const isEditing = !!initialData?.id;

  // Initialize form state
  const [formData, setFormData] = useState({
    customerName: initialData?.customerName || '',
    serviceName: initialData?.serviceName || '',
    spaceId: initialData?.spaceId || (spaces.length > 0 ? spaces[0].id : ''),
    date: initialData?.date || new Date().toISOString().split('T')[0],
    startTime: initialData?.startTime || '09:00',
    endTime: '', // Calculated via useEffect on mount
    durationMinutes: initialData?.durationMinutes || 60,
    breakMinutes: initialData?.breakMinutes || 0,
    pax: initialData?.pax || 1,
    status: initialData?.status || BookingStatus.CONFIRMED,
    isPaid: initialData?.isPaid || false,
  });

  // Calculate initial EndTime if not present or on load
  useEffect(() => {
    const startMins = timeToMins(formData.startTime);
    const endMins = startMins + Number(formData.durationMinutes);
    setFormData(prev => ({ ...prev, endTime: minsToTime(endMins) }));
  }, []); // Run once on mount

  const [capacityInfo, setCapacityInfo] = useState<{
      currentLoad: number;
      max: number;
      remaining: number;
      isOver: boolean;
  } | null>(null);

  // --- Handlers for synchronized time fields ---

  const handleStartTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newStart = e.target.value;
      const startMins = timeToMins(newStart);
      const endMins = startMins + Number(formData.durationMinutes);
      setFormData(prev => ({
          ...prev,
          startTime: newStart,
          endTime: minsToTime(endMins)
      }));
  };

  const handleEndTimeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const newEnd = e.target.value;
      const endMins = timeToMins(newEnd);
      const startMins = timeToMins(formData.startTime);

      let duration = endMins - startMins;
      // Force minimum duration of 15 mins to avoid issues
      if (duration < 15) duration = 15; 

      setFormData(prev => ({
          ...prev,
          endTime: newEnd,
          durationMinutes: duration
      }));
  };

  const handleDurationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const duration = Number(e.target.value);
      const startMins = timeToMins(formData.startTime);
      const endMins = startMins + duration;

      setFormData(prev => ({
          ...prev,
          durationMinutes: duration,
          endTime: minsToTime(endMins)
      }));
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const togglePayment = () => {
      setFormData(prev => ({ ...prev, isPaid: !prev.isPaid }));
  };

  const setStatus = (status: BookingStatus) => {
      setFormData(prev => ({ ...prev, status }));
  };

  // --- Capacity Calculation ---
  useEffect(() => {
    try {
        calculateCapacity();
    } catch (e) {
        console.error("Error calculating capacity", e);
    }
  }, [formData.spaceId, formData.date, formData.startTime, formData.durationMinutes, formData.pax]);

  const calculateCapacity = () => {
      if (!formData.spaceId) return;
      const space = spaces.find(s => s.id === formData.spaceId);
      if (!space) return;

      const newStart = timeToMins(formData.startTime);
      const newEnd = newStart + Number(formData.durationMinutes) + Number(formData.breakMinutes);

      const concurrent = currentBookings.filter(b => {
          if (b.spaceId !== formData.spaceId) return false;
          if (b.date !== formData.date) return false;
          if (initialData && b.id === initialData.id) return false;
          if (b.status === BookingStatus.CANCELED) return false;

          const bStart = timeToMins(b.startTime);
          const bEnd = bStart + b.durationMinutes + (b.breakMinutes || 0);

          return (newStart < bEnd && newEnd > bStart);
      });

      const currentLoad = concurrent.reduce((sum, b) => sum + (b.pax || 1), 0);
      const newPax = Number(formData.pax);
      const totalLoad = currentLoad + newPax;

      setCapacityInfo({
          currentLoad,
          max: space.capacity,
          remaining: Math.max(0, space.capacity - currentLoad),
          isOver: totalLoad > space.capacity
      });
  };

  // Manual Trigger for Submission to prevent ghost submissions
  const triggerSubmit = () => {
    onSubmit({
        ...formData,
        serviceName: formData.serviceName || 'Réservation', // Default if empty
        durationMinutes: Number(formData.durationMinutes),
        breakMinutes: Number(formData.breakMinutes),
        pax: Number(formData.pax)
    });
  };

  const handleDelete = () => {
      if(window.confirm("Supprimer cette réservation ?")) {
          onDelete?.();
      }
  }

  const nextStep = () => {
      if (currentStep === 1) {
          if (!formData.customerName) return; // Only customerName is required
      }
      if (currentStep === 2) {
          if (!formData.spaceId) {
             alert("Veuillez sélectionner un espace.");
             return;
          }
      }
      setCurrentStep(p => Math.min(STEPS.length, p + 1));
  };

  const prevStep = () => {
      setCurrentStep(p => Math.max(1, p - 1));
  };

  // Robust Enter key handling
  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
          e.preventDefault(); // Always prevent default form submit
          // Only allow navigation on earlier steps
          if (currentStep < STEPS.length) {
             nextStep();
          }
          // On last step, do nothing. User must click confirm.
      }
  };

  if (spaces.length === 0) {
      return (
          <div className="text-center py-8 text-slate-500">
              <p>Aucun espace configuré.</p>
              <p className="text-sm mt-2">Veuillez créer des espaces dans les paramètres.</p>
              <Button variant="secondary" onClick={onCancel} className="mt-4">Fermer</Button>
          </div>
      );
  }

  return (
    <form 
        onSubmit={(e) => e.preventDefault()} 
        onKeyDown={handleKeyDown} 
        className="flex flex-col h-full"
        autoComplete="off"
    >
      {/* Quick Actions Header (Only when Editing) */}
      {isEditing && (
          <div className="mb-6 mx-1 p-2 bg-white rounded-xl border border-slate-200 shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] flex items-center justify-between gap-3 animate-in slide-in-from-top-2">
               <div className="flex gap-2">
                   <button
                       type="button"
                       onClick={() => setStatus(BookingStatus.CHECKED_IN)}
                       className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${formData.status === BookingStatus.CHECKED_IN ? 'bg-emerald-100 text-emerald-700 border border-emerald-200 shadow-sm' : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-white hover:shadow-sm'}`}
                   >
                       <UserCheck size={14} /> Présent
                   </button>
                   <button
                       type="button"
                       onClick={() => setStatus(BookingStatus.NO_SHOW)}
                       className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-colors ${formData.status === BookingStatus.NO_SHOW ? 'bg-zinc-100 text-zinc-700 border border-zinc-200 shadow-sm' : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-white hover:shadow-sm'}`}
                   >
                       <UserX size={14} /> No-Show
                   </button>
               </div>

               <button
                    type="button"
                    onClick={togglePayment}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-all border shadow-sm ${formData.isPaid ? 'bg-teal-50 border-teal-200 text-teal-700' : 'bg-white border-orange-200 text-orange-600 hover:bg-orange-50'}`}
               >
                   {formData.isPaid ? <Check size={14} /> : <CreditCard size={14} />}
                   {formData.isPaid ? 'Réglé' : 'À régler'}
               </button>
          </div>
      )}

      {/* Compact Progress Bar - Added pt-5 to prevent top clipping */}
      <div className={`${isEditing ? 'mb-6' : 'mb-8 pt-5'} px-4`}>
          <div className="flex items-center justify-between relative">
              <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-0.5 bg-slate-100 -z-10 rounded-full"></div>
              <div 
                className="absolute left-0 top-1/2 transform -translate-y-1/2 h-0.5 bg-teal-500 -z-10 rounded-full transition-all duration-300" 
                style={{ width: `${((currentStep - 1) / (STEPS.length - 1)) * 100}%` }}
              ></div>

              {STEPS.map((step) => {
                  const Icon = step.icon;
                  const isActive = step.id === currentStep;
                  const isCompleted = step.id < currentStep;

                  return (
                      <div key={step.id} className="flex flex-col items-center relative group">
                          <div className={`
                              w-8 h-8 rounded-full flex items-center justify-center border-2 transition-all duration-300 z-10
                              ${isActive ? 'bg-teal-600 border-teal-600 text-white shadow-lg shadow-teal-200 scale-125' : 
                                isCompleted ? 'bg-teal-600 border-teal-600 text-white' : 'bg-white border-slate-200 text-slate-300'}
                          `}>
                              {isCompleted ? <Check size={14} /> : <Icon size={14} />}
                          </div>
                          <div className={`absolute -bottom-6 left-1/2 transform -translate-x-1/2 whitespace-nowrap text-[10px] font-bold uppercase tracking-wider transition-colors duration-300 ${isActive ? 'text-teal-700' : 'text-slate-300'}`}>
                             {step.title}
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="flex-1 min-h-[320px]">
        {/* Step 1: Info Client */}
        {currentStep === 1 && (
            <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="group">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Client</label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-teal-500 transition-colors" size={18}/>
                        <input
                            type="text"
                            name="customerName"
                            required
                            value={formData.customerName}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 pl-10 pr-4 text-sm transition-all"
                            placeholder="Nom complet"
                            autoFocus
                        />
                    </div>
                </div>

                <div className="group">
                    <div className="flex justify-between items-center mb-1.5 ml-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">Prestation</label>
                        <span className="text-[10px] text-slate-400 italic font-medium">Optionnel</span>
                    </div>
                    <input
                        type="text"
                        name="serviceName"
                        value={formData.serviceName}
                        onChange={handleChange}
                        className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-3 px-4 text-sm transition-all"
                        placeholder="Ex: Massage, Soin visage..."
                    />
                </div>
            </div>
        )}

        {/* Step 2: Date, Space & Times */}
        {currentStep === 2 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Espace</label>
                    <div className="grid grid-cols-2 gap-2 max-h-32 overflow-y-auto pr-1 custom-scrollbar">
                        {spaces.map(space => (
                            <div 
                                key={space.id}
                                onClick={() => setFormData(prev => ({ ...prev, spaceId: space.id }))}
                                className={`cursor-pointer px-3 py-2 rounded-lg border-2 transition-all ${formData.spaceId === space.id ? 'bg-teal-50/50 border-teal-500' : 'bg-slate-50 border-transparent hover:bg-slate-100'}`}
                            >
                                <div className={`font-semibold text-xs ${formData.spaceId === space.id ? 'text-teal-900' : 'text-slate-700'}`}>{space.name}</div>
                                <div className="text-[10px] text-slate-500 mt-0.5">{space.type}</div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                     <div className="group">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Date</label>
                        <div className="relative">
                            <input
                                type="date"
                                name="date"
                                required
                                value={formData.date}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-2 text-sm transition-all"
                            />
                            <CalendarIcon size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                    <div>
                         {/* Linked Duration Field */}
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Durée (min)</label>
                         <input
                            type="number"
                            name="durationMinutes"
                            required
                            min="15"
                            step="5"
                            value={formData.durationMinutes}
                            onChange={handleDurationChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm font-medium"
                        />
                    </div>
                </div>

                {/* Time Range with End Time */}
                <div className="flex items-center gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100">
                    <div className="flex-1">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Début</label>
                        <input
                            type="time"
                            name="startTime"
                            required
                            value={formData.startTime}
                            onChange={handleStartTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0"
                        />
                    </div>
                    <ArrowRight size={20} className="text-slate-300" />
                    <div className="flex-1 text-right">
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">Fin</label>
                        <input
                            type="time"
                            name="endTime"
                            required
                            value={formData.endTime}
                            onChange={handleEndTimeChange}
                            className="w-full bg-transparent font-bold text-lg text-slate-700 outline-none p-0 border-none focus:ring-0 text-right"
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Step 3: Details & Confirmation */}
        {currentStep === 3 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">

                {/* Capacity Alert */}
                {capacityInfo && (
                    <div className={`p-3 rounded-lg text-xs border flex items-center gap-3 ${capacityInfo.isOver ? 'bg-red-50 border-red-100 text-red-700' : 'bg-emerald-50 border-emerald-100 text-emerald-700'}`}>
                        {capacityInfo.isOver ? <AlertTriangle className="flex-shrink-0" size={18} /> : <Check className="flex-shrink-0" size={18} />}
                        <div>
                            <span className="font-bold block">{capacityInfo.isOver ? "Surbooking !" : "Créneau disponible"}</span>
                            <span className="opacity-80">Charge: {capacityInfo.currentLoad}/{capacityInfo.max} pers.</span>
                        </div>
                    </div>
                )}

                {/* Info Row */}
                <div className="bg-slate-50 rounded-xl p-3 border border-slate-100 flex justify-between items-center text-sm">
                    <span className="text-slate-500">Horaire prévu</span>
                    <span className="font-bold text-slate-800">{formData.startTime} - {formData.endTime} ({formData.durationMinutes} min)</span>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Personnes</label>
                        <div className="relative">
                            <input
                                type="number"
                                name="pax"
                                required
                                min="1"
                                value={formData.pax}
                                onChange={handleChange}
                                className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 pl-9 pr-3 text-sm"
                            />
                            <Users size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        </div>
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Pause (Nettoyage)</label>
                        <select
                            name="breakMinutes"
                            value={formData.breakMinutes}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                        >
                            <option value="0">Aucune</option>
                            <option value="15">15 min</option>
                            <option value="30">30 min</option>
                            <option value="60">1h</option>
                        </select>
                    </div>
                </div>

                {/* Status & Payment Row (Also in Quick Actions but detailed here) */}
                <div className="grid grid-cols-2 gap-3">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Statut</label>
                        <select
                            name="status"
                            value={formData.status}
                            onChange={handleChange}
                            className="w-full rounded-xl bg-slate-50 border-transparent focus:bg-white border-2 focus:border-teal-500 focus:ring-0 py-2.5 px-3 text-sm"
                        >
                            {Object.values(BookingStatus).map(s => (
                            <option key={s} value={s}>{STATUS_LABELS[s]}</option>
                            ))}
                        </select>
                    </div>

                    {/* Payment Toggle */}
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1">Règlement</label>
                        <button
                            type="button"
                            onClick={togglePayment}
                            className={`w-full rounded-xl border-2 flex items-center justify-between px-3 py-2.5 transition-all ${formData.isPaid ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                        >
                            <span className="text-sm font-medium">{formData.isPaid ? 'Réglé' : 'À régler'}</span>
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center ${formData.isPaid ? 'bg-emerald-500 text-white' : 'bg-slate-200'}`}>
                                <CreditCard size={12} />
                            </div>
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <div className="pt-4 mt-2 flex items-center justify-between">

        {/* Left Side: Delete */}
        <div>
            {onDelete && (
                <button type="button" onClick={handleDelete} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50" title="Supprimer">
                    <Trash2 size={18} />
                </button>
            )}
        </div>

        {/* Right Side: Navigation */}
        <div className="flex gap-2">
            {currentStep === 1 ? (
                <Button type="button" variant="ghost" onClick={onCancel} className="text-slate-500">
                    Annuler
                </Button>
            ) : (
                <Button type="button" variant="secondary" onClick={prevStep}>
                    Retour
                </Button>
            )}

            {currentStep < STEPS.length ? (
                <Button 
                    type="button" 
                    variant="primary" 
                    onClick={nextStep}
                    disabled={currentStep === 1 && !formData.customerName}
                    className="pl-5 pr-4"
                >
                    Suivant <ChevronRight size={16} className="ml-1" />
                </Button>
            ) : (
                <Button 
                    type="button" // Changed to explicit button type to prevent form submit race conditions
                    onClick={triggerSubmit}
                    variant={capacityInfo?.isOver ? "danger" : "primary"}
                    className="shadow-lg shadow-teal-500/30"
                >
                    {capacityInfo?.isOver ? "Forcer" : "Confirmer"}
                </Button>
            )}
        </div>
    </form>
  );
};
